--
-- TOC entry 1589 (class 1255 OID 31888)
-- Name: accept_booking("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."accept_booking"("p_booking_id" "uuid", "p_coach_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_booking RECORD;
  v_coach_id UUID;
  v_session_id UUID;
BEGIN
  SELECT id INTO v_coach_id
  FROM public.coach_profiles
  WHERE user_id = p_coach_user_id;

  IF v_coach_id IS NULL THEN
    RAISE EXCEPTION 'Coach profile not found';
  END IF;

  SELECT * INTO v_booking
  FROM public.session_bookings
  WHERE id = p_booking_id
    AND coach_id = v_coach_id
    AND status = 'pending';

  IF v_booking IS NULL THEN
    RAISE EXCEPTION 'Booking not found or already processed';
  END IF;

  UPDATE public.session_bookings
  SET status = 'accepted', updated_at = NOW()
  WHERE id = p_booking_id;

  INSERT INTO public.coaching_sessions (
    booking_id,
    sailor_id,
    coach_id,
    start_time,
    end_time,
    session_type,
    total_amount_cents,
    status,
    payment_status
  )
  VALUES (
    p_booking_id,
    v_booking.sailor_id,
    v_booking.coach_id,
    v_booking.requested_start_time,
    v_booking.requested_end_time,
    COALESCE(v_booking.session_type, 'on_water'),
    v_booking.total_amount_cents,
    'scheduled',
    'pending'
  )
  RETURNING id INTO v_session_id;

  IF v_booking.availability_slot_id IS NOT NULL THEN
    UPDATE public.coach_availability
    SET is_active = false, updated_at = NOW()
    WHERE id = v_booking.availability_slot_id;
  END IF;

  RETURN v_session_id;
END;
$$;


ALTER FUNCTION "public"."accept_booking"("p_booking_id" "uuid", "p_coach_user_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 1707 (class 1255 OID 166960)
-- Name: accept_team_invite("text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."accept_team_invite"("p_invite_code" "text", "p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_team subscription_teams%ROWTYPE;
  v_member subscription_team_members%ROWTYPE;
  v_user_email TEXT;
  v_seat_count INTEGER;
BEGIN
  -- Get user email
  SELECT email INTO v_user_email FROM auth.users WHERE id = p_user_id;

  IF v_user_email IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'User not found');
  END IF;

  -- Find team by invite code
  SELECT * INTO v_team FROM subscription_teams WHERE invite_code = p_invite_code;

  IF v_team IS NULL THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid invite code');
  END IF;

  -- Check if user is already a member
  SELECT * INTO v_member FROM subscription_team_members
  WHERE team_id = v_team.id AND (user_id = p_user_id OR email = v_user_email);

  IF v_member IS NOT NULL AND v_member.status = 'active' THEN
    RETURN jsonb_build_object('success', false, 'error', 'Already a member of this team');
  END IF;

  -- Check seat availability
  SELECT COUNT(*) INTO v_seat_count FROM subscription_team_members
  WHERE team_id = v_team.id AND status = 'active';

  IF v_seat_count >= v_team.max_seats THEN
    RETURN jsonb_build_object('success', false, 'error', 'Team is full');
  END IF;

  -- If pending invite exists, activate it
  IF v_member IS NOT NULL THEN
    UPDATE subscription_team_members
    SET user_id = p_user_id, status = 'active', joined_at = NOW()
    WHERE id = v_member.id;
  ELSE
    -- Create new membership
    INSERT INTO subscription_team_members (team_id, user_id, email, role, status, joined_at)
    VALUES (v_team.id, p_user_id, v_user_email, 'member', 'active', NOW());
  END IF;

  -- Link user profile to team
  UPDATE profiles SET subscription_team_id = v_team.id WHERE id = p_user_id;

  -- Update user's subscription tier to match team owner's tier
  UPDATE users
  SET subscription_tier = (SELECT subscription_tier FROM users WHERE id = v_team.owner_id),
      subscription_status = (SELECT subscription_status FROM users WHERE id = v_team.owner_id)
  WHERE id = p_user_id;

  RETURN jsonb_build_object(
    'success', true,
    'team_id', v_team.id,
    'team_name', v_team.name
  );
END;
$$;


ALTER FUNCTION "public"."accept_team_invite"("p_invite_code" "text", "p_user_id" "uuid") OWNER TO "postgres";

