--
-- TOC entry 1682 (class 1255 OID 162353)
-- Name: calculate_hot_score(integer, integer, integer, timestamp with time zone, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."calculate_hot_score"("p_upvotes" integer, "p_comments" integer, "p_views" integer, "p_created_at" timestamp with time zone, "p_pinned" boolean) RETURNS numeric
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  age_hours NUMERIC;
  score NUMERIC;
BEGIN
  IF p_pinned THEN
    RETURN 999999999;
  END IF;

  age_hours := EXTRACT(EPOCH FROM (now() - p_created_at)) / 3600.0;
  score := (COALESCE(p_upvotes, 0) * 2 + COALESCE(p_comments, 0) * 3 + LEAST(COALESCE(p_views, 0), 100))
           / POWER(age_hours + 2, 1.5);
  RETURN score;
END;
$$;


ALTER FUNCTION "public"."calculate_hot_score"("p_upvotes" integer, "p_comments" integer, "p_views" integer, "p_created_at" timestamp with time zone, "p_pinned" boolean) OWNER TO "postgres";

