-- TOC entry 1746 (class 1255 OID 202795)
-- Name: can_manage_org_content("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."can_manage_org_content"("p_org_id" "uuid", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT (
    auth.uid() IS NOT NULL
    AND (
      p_created_by = auth.uid()
      OR (
        p_org_id IS NOT NULL
        AND public.has_org_role(
          p_org_id,
          ARRAY['owner', 'admin', 'manager', 'faculty', 'instructor']::text[],
          auth.uid(),
          false
        )
      )
    )
  );
$$;


ALTER FUNCTION "public"."can_manage_org_content"("p_org_id" "uuid", "p_created_by" "uuid") OWNER TO "postgres";

--
-- TOC entry 1779 (class 1255 OID 225470)
-- Name: can_subscribe_to_blueprint("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."can_subscribe_to_blueprint"("p_blueprint_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_access_level text;
  v_org_id uuid;
  v_is_published boolean;
  v_has_purchase boolean;
BEGIN
  SELECT access_level, organization_id, is_published
  INTO v_access_level, v_org_id, v_is_published
  FROM timeline_blueprints
  WHERE id = p_blueprint_id;

  IF NOT FOUND OR NOT v_is_published THEN RETURN false; END IF;
  IF v_access_level = 'public' THEN RETURN true; END IF;
  IF v_access_level = 'org_members' THEN
    RETURN is_org_active_member(v_org_id);
  END IF;
  IF v_access_level = 'paid' THEN
    -- Allow if org member (free access for org members)
    IF v_org_id IS NOT NULL AND is_org_active_member(v_org_id) THEN
      RETURN true;
    END IF;
    -- Allow if user has completed purchase
    SELECT EXISTS (
      SELECT 1 FROM blueprint_purchases
      WHERE blueprint_id = p_blueprint_id
        AND buyer_id = auth.uid()
        AND status = 'completed'
    ) INTO v_has_purchase;
    RETURN v_has_purchase;
  END IF;
  RETURN false;
END;
$$;


ALTER FUNCTION "public"."can_subscribe_to_blueprint"("p_blueprint_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 1747 (class 1255 OID 202796)
-- Name: can_view_org_scoped_content("uuid", "text", "text"[], boolean, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."can_view_org_scoped_content"("p_org_id" "uuid", "p_visibility" "text", "p_allowed_roles" "text"[] DEFAULT '{}'::"text"[], "p_requires_verified" boolean DEFAULT false, "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF p_visibility = 'public' THEN
    RETURN true;
  END IF;

  IF auth.uid() IS NULL THEN
    RETURN false;
  END IF;

  IF p_visibility = 'authenticated' THEN
    RETURN true;
  END IF;

  IF p_visibility = 'private' THEN
    RETURN public.can_manage_org_content(p_org_id, p_created_by);
  END IF;

  IF p_org_id IS NULL THEN
    RETURN false;
  END IF;

  IF p_visibility = 'org_members' THEN
    RETURN public.is_active_org_member(p_org_id, auth.uid(), p_requires_verified);
  END IF;

  IF p_visibility = 'org_roles' THEN
    RETURN public.has_org_role(p_org_id, p_allowed_roles, auth.uid(), p_requires_verified);
  END IF;

  RETURN false;
END;
$$;


ALTER FUNCTION "public"."can_view_org_scoped_content"("p_org_id" "uuid", "p_visibility" "text", "p_allowed_roles" "text"[], "p_requires_verified" boolean, "p_created_by" "uuid") OWNER TO "postgres";

--
-- TOC entry 1749 (class 1255 OID 202942)
-- Name: capture_marketing_revision(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."capture_marketing_revision"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_page_id uuid;
  v_entity_id uuid;
  v_snapshot jsonb;
  v_op text;
  v_source text;
begin
  v_source := coalesce(TG_ARGV[0], 'page');

  if TG_OP = 'DELETE' then
    v_snapshot := to_jsonb(old);
  else
    v_snapshot := to_jsonb(new);
  end if;

  if TG_TABLE_NAME = 'marketing_pages' then
    v_page_id := coalesce(new.id, old.id);
    v_entity_id := v_page_id;
  else
    v_page_id := coalesce(new.page_id, old.page_id);
    v_entity_id := coalesce(new.id, old.id);
  end if;

  v_op := lower(TG_OP);

  insert into public.marketing_page_revisions (
    page_id,
    revision_source,
    entity_id,
    operation,
    changed_by,
    snapshot
  )
  values (
    v_page_id,
    v_source,
    v_entity_id,
    v_op,
    auth.uid(),
    v_snapshot
  );

  if TG_OP = 'DELETE' then
    return old;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."capture_marketing_revision"() OWNER TO "postgres";

--
-- TOC entry 1581 (class 1255 OID 26998)
-- Name: check_equipment_maintenance_due(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."check_equipment_maintenance_due"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  product_record RECORD;
  months_since_purchase INTEGER;
  alert_exists BOOLEAN;
BEGIN
  IF NEW.status != 'active' THEN
    RETURN NEW;
  END IF;

  SELECT * INTO product_record FROM equipment_products WHERE id = NEW.product_id;

  IF product_record IS NOT NULL THEN
    IF product_record.expected_lifespan_hours IS NOT NULL
       AND NEW.total_usage_hours >= product_record.expected_lifespan_hours * 0.8 THEN

      SELECT EXISTS(
        SELECT 1 FROM equipment_alerts
        WHERE equipment_id = NEW.id AND alert_type = 'replacement_recommended' AND status = 'active'
      ) INTO alert_exists;

      IF NOT alert_exists THEN
        INSERT INTO equipment_alerts (
          sailor_id, equipment_id, alert_type, severity, title, message, ai_generated, recommended_action
        ) VALUES (
          NEW.sailor_id, NEW.id, 'replacement_recommended', 'warning',
          NEW.custom_name || ' nearing end of life',
          'This equipment has ' || NEW.total_usage_hours || ' racing hours. Manufacturer recommends replacement at ' || product_record.expected_lifespan_hours || ' hours.',
          true, 'Consider inspecting or replacing before next major regatta'
        );
      END IF;
    END IF;

    IF product_record.expected_lifespan_months IS NOT NULL AND NEW.purchase_date IS NOT NULL THEN
      months_since_purchase := EXTRACT(YEAR FROM AGE(CURRENT_DATE, NEW.purchase_date)) * 12
                              + EXTRACT(MONTH FROM AGE(CURRENT_DATE, NEW.purchase_date));

      IF months_since_purchase >= product_record.expected_lifespan_months * 0.8 THEN
        SELECT EXISTS(
          SELECT 1 FROM equipment_alerts
          WHERE equipment_id = NEW.id AND alert_type = 'maintenance_due' AND status = 'active'
        ) INTO alert_exists;

        IF NOT alert_exists THEN
          INSERT INTO equipment_alerts (
            sailor_id, equipment_id, alert_type, severity, title, message, ai_generated, recommended_action
          ) VALUES (
            NEW.sailor_id, NEW.id, 'maintenance_due', 'warning',
            NEW.custom_name || ' age-based maintenance due',
            'This equipment is ' || months_since_purchase || ' months old. Consider inspection or replacement.',
            true, 'Schedule maintenance or replacement'
          );
        END IF;
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."check_equipment_maintenance_due"() OWNER TO "postgres";

