--

CREATE FUNCTION "public"."check_notification_preference"("p_user_id" "uuid", "p_category" "text") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_enabled BOOLEAN;
BEGIN
  EXECUTE format(
    'SELECT COALESCE(%I, true) FROM notification_preferences WHERE user_id = $1',
    p_category
  ) INTO v_enabled USING p_user_id;

  -- If no row exists, default to true (opt-in by default)
  RETURN COALESCE(v_enabled, true);
END;
$_$;


