--
-- TOC entry 1803 (class 1255 OID 244183)
-- Name: cleanup_blueprint_step_action_on_delete(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."cleanup_blueprint_step_action_on_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only act when the deleted row was adopted from a blueprint
  IF OLD.source_blueprint_id IS NULL OR OLD.source_id IS NULL THEN
    RETURN OLD;
  END IF;

  DELETE FROM blueprint_step_actions
   WHERE source_step_id = OLD.source_id
     AND subscription_id IN (
       SELECT id
         FROM blueprint_subscriptions
        WHERE blueprint_id = OLD.source_blueprint_id
          AND subscriber_id = OLD.user_id
     );

  RETURN OLD;
END;
$$;


ALTER FUNCTION "public"."cleanup_blueprint_step_action_on_delete"() OWNER TO "postgres";

