--
-- TOC entry 1697 (class 1255 OID 166485)
-- Name: create_comment_notification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_comment_notification"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor_name TEXT;
  v_race_name TEXT;
  v_race_owner UUID;
  v_parent_author UUID;
BEGIN
  -- Get commenter's name from profiles table
  SELECT full_name INTO v_actor_name
  FROM profiles
  WHERE id = NEW.user_id;

  -- Get race info
  SELECT name, owner_id INTO v_race_name, v_race_owner
  FROM regattas
  WHERE id = NEW.regatta_id;

  -- If this is a reply, notify the parent comment author
  IF NEW.parent_id IS NOT NULL THEN
    SELECT user_id INTO v_parent_author
    FROM regatta_comments
    WHERE id = NEW.parent_id;

    -- Don't notify if replying to own comment
    IF v_parent_author IS NOT NULL AND v_parent_author != NEW.user_id THEN
      INSERT INTO social_notifications (user_id, type, actor_id, regatta_id, comment_id, title, body)
      VALUES (
        v_parent_author,
        'race_comment_reply',
        NEW.user_id,
        NEW.regatta_id,
        NEW.id,
        COALESCE(v_actor_name, 'Someone') || ' replied to your comment',
        LEFT(NEW.content, 100)
      );
    END IF;
  END IF;

  -- Notify race owner (if not commenting on own race and not already notified as parent author)
  IF v_race_owner != NEW.user_id AND (v_parent_author IS NULL OR v_race_owner != v_parent_author) THEN
    INSERT INTO social_notifications (user_id, type, actor_id, regatta_id, comment_id, title, body)
    VALUES (
      v_race_owner,
      'race_comment',
      NEW.user_id,
      NEW.regatta_id,
      NEW.id,
      COALESCE(v_actor_name, 'Someone') || ' commented on your race',
      LEFT(NEW.content, 100)
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."create_comment_notification"() OWNER TO "postgres";

--
-- TOC entry 1677 (class 1255 OID 154941)
-- Name: create_direct_invite("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_direct_invite"("p_regatta_id" "uuid", "p_target_user_id" "uuid", "p_access_level" "text" DEFAULT 'view'::"text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_owner_id UUID := auth.uid();
  v_collaborator_id UUID;
  v_invite_code TEXT;
  v_target_profile RECORD;
BEGIN
  -- Check if caller owns this regatta
  IF NOT EXISTS (
    SELECT 1 FROM regattas WHERE id = p_regatta_id AND created_by = v_owner_id
  ) THEN
    RETURN json_build_object('success', false, 'error', 'Not authorized to invite to this race');
  END IF;

  -- Check if target user exists
  IF NOT EXISTS (
    SELECT 1 FROM auth.users WHERE id = p_target_user_id
  ) THEN
    RETURN json_build_object('success', false, 'error', 'Target user not found');
  END IF;

  -- Check if target user is already a collaborator on this race
  IF EXISTS (
    SELECT 1 FROM race_collaborators
    WHERE regatta_id = p_regatta_id AND user_id = p_target_user_id
  ) THEN
    RETURN json_build_object('success', false, 'error', 'User is already a collaborator on this race');
  END IF;

  -- Get target user's display name from sailor_profiles or profiles
  SELECT sp.full_name AS sailor_name, p.full_name AS profile_name
  INTO v_target_profile
  FROM auth.users u
  LEFT JOIN sailor_profiles sp ON sp.user_id = u.id
  LEFT JOIN profiles p ON p.id = u.id
  WHERE u.id = p_target_user_id;

  -- Create the collaborator record with user_id set immediately
  -- This makes the race appear in the target user's timeline as a pending invite
  INSERT INTO race_collaborators (
    regatta_id,
    user_id,
    invited_by,
    access_level,
    display_name,
    status
  )
  VALUES (
    p_regatta_id,
    p_target_user_id,
    v_owner_id,
    p_access_level,
    COALESCE(v_target_profile.sailor_name, v_target_profile.profile_name),
    'pending'
  )
  RETURNING id INTO v_collaborator_id;

  -- Generate invite code as backup (for sharing via link/message)
  v_invite_code := set_race_collaborator_invite_code(v_collaborator_id);

  RETURN json_build_object(
    'success', true,
    'collaborator_id', v_collaborator_id,
    'invite_code', v_invite_code
  );
END;
$$;


ALTER FUNCTION "public"."create_direct_invite"("p_regatta_id" "uuid", "p_target_user_id" "uuid", "p_access_level" "text") OWNER TO "postgres";

--
-- TOC entry 12363 (class 0 OID 0)
-- Dependencies: 1677
-- Name: FUNCTION "create_direct_invite"("p_regatta_id" "uuid", "p_target_user_id" "uuid", "p_access_level" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."create_direct_invite"("p_regatta_id" "uuid", "p_target_user_id" "uuid", "p_access_level" "text") IS 'Creates a pending collaboration invite for a specific user. The race will appear in their timeline with a pending status until they accept or decline.';


