--
-- TOC entry 1824 (class 1255 OID 245664)
-- Name: create_share_token("text", "uuid", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_share_token"("p_target_type" "text", "p_target_id" "uuid", "p_expires_at" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_caller UUID := auth.uid();
  v_owns BOOLEAN := false;
  v_scope TEXT;
  v_token TEXT;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'authentication required' USING ERRCODE = '42501';
  END IF;

  IF p_target_type = 'step' THEN
    SELECT EXISTS (
      SELECT 1 FROM public.timeline_steps
      WHERE id = p_target_id AND user_id = v_caller
    ) INTO v_owns;
    v_scope := 'step:read';
  ELSIF p_target_type = 'blueprint' THEN
    SELECT EXISTS (
      SELECT 1 FROM public.timeline_blueprints
      WHERE id = p_target_id AND user_id = v_caller
    ) INTO v_owns;
    v_scope := 'blueprint:read';
  ELSE
    RAISE EXCEPTION 'unsupported target_type %', p_target_type USING ERRCODE = '22023';
  END IF;

  IF NOT v_owns THEN
    RAISE EXCEPTION 'caller does not own target' USING ERRCODE = '42501';
  END IF;

  v_token := encode(gen_random_bytes(32), 'hex');

  INSERT INTO public.share_tokens (
    target_type, target_id, scope, token, created_by, expires_at
  ) VALUES (
    p_target_type, p_target_id, v_scope, v_token, v_caller, p_expires_at
  );

  RETURN v_token;
END;
$$;


ALTER FUNCTION "public"."create_share_token"("p_target_type" "text", "p_target_id" "uuid", "p_expires_at" timestamp with time zone) OWNER TO "postgres";

