--
-- TOC entry 1802 (class 1255 OID 244181)
-- Name: create_timeline_step("jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_timeline_step"("p_input" "jsonb") RETURNS SETOF "public"."timeline_steps"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  v_user_id UUID := (p_input->>'user_id')::UUID;
  v_interest_id UUID := (p_input->>'interest_id')::UUID;
  v_visibility TEXT;
  v_sort_order INTEGER;
  v_sort_key TEXT;
  v_starts_at TIMESTAMPTZ;
BEGIN
  -- Visibility: explicit value wins; otherwise run the cascade
  IF p_input ? 'visibility' AND p_input->>'visibility' IS NOT NULL THEN
    v_visibility := p_input->>'visibility';
  ELSE
    SELECT COALESCE(
      (
        SELECT up.interest_visibility_defaults ->> (v_interest_id::TEXT)
          FROM user_preferences up
         WHERE up.user_id = v_user_id
         LIMIT 1
      ),
      (
        SELECT p.default_step_visibility
          FROM profiles p
         WHERE p.id = v_user_id
         LIMIT 1
      ),
      'followers'
    ) INTO v_visibility;
  END IF;

  -- sort_order: explicit value wins; otherwise compute "top of planned" as
  -- MIN(sort_order) - 1 across the user's planned rows in BOTH tables.
  IF p_input ? 'sort_order' AND p_input->>'sort_order' IS NOT NULL THEN
    v_sort_order := (p_input->>'sort_order')::INTEGER;
  ELSE
    SELECT COALESCE(
      (
        SELECT MIN(s) - 1
        FROM (
          SELECT sort_order AS s
            FROM timeline_steps
           WHERE user_id = v_user_id
             AND status IS DISTINCT FROM 'completed'
          UNION ALL
          SELECT sort_order AS s
            FROM regattas
           WHERE created_by = v_user_id
             AND status IS DISTINCT FROM 'completed'
        ) planned
      ),
      0
    ) INTO v_sort_order;
  END IF;

  -- sort_key: pass through when supplied, else NULL.
  IF p_input ? 'sort_key' AND p_input->>'sort_key' IS NOT NULL THEN
    v_sort_key := p_input->>'sort_key';
  ELSE
    v_sort_key := NULL;
  END IF;

  -- starts_at: caller may pass explicit null to mean "unscheduled"; only
  -- default to NOW() when the key is absent entirely.
  IF p_input ? 'starts_at' THEN
    v_starts_at := NULLIF(p_input->>'starts_at', '')::TIMESTAMPTZ;
  ELSE
    v_starts_at := NOW();
  END IF;

  RETURN QUERY
  INSERT INTO timeline_steps (
    user_id,
    interest_id,
    organization_id,
    program_session_id,
    source_type,
    source_id,
    title,
    description,
    category,
    status,
    starts_at,
    ends_at,
    location_name,
    location_lat,
    location_lng,
    location_place_id,
    visibility,
    share_approximate_location,
    sort_order,
    sort_key,
    metadata
  ) VALUES (
    v_user_id,
    v_interest_id,
    NULLIF(p_input->>'organization_id', '')::UUID,
    NULLIF(p_input->>'program_session_id', '')::UUID,
    COALESCE(p_input->>'source_type', 'manual'),
    NULLIF(p_input->>'source_id', '')::UUID,
    p_input->>'title',
    p_input->>'description',
    COALESCE(p_input->>'category', 'general'),
    COALESCE(p_input->>'status', 'pending'),
    v_starts_at,
    NULLIF(p_input->>'ends_at', '')::TIMESTAMPTZ,
    p_input->>'location_name',
    NULLIF(p_input->>'location_lat', '')::DOUBLE PRECISION,
    NULLIF(p_input->>'location_lng', '')::DOUBLE PRECISION,
    p_input->>'location_place_id',
    v_visibility,
    COALESCE((p_input->>'share_approximate_location')::BOOLEAN, FALSE),
    v_sort_order,
    v_sort_key,
    COALESCE(p_input->'metadata', '{}'::jsonb)
  )
  RETURNING *;
END;
$$;


