--
-- TOC entry 1771 (class 1255 OID 210415)
-- Name: ensure_profile_for_user("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."ensure_profile_for_user"("p_user_id" "uuid", "p_user_email" "text" DEFAULT NULL::"text", "p_user_full_name" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $_$
DECLARE
  profiles_relkind "char";
  has_id boolean;
  has_user_id boolean;
  has_email boolean;
  has_full_name boolean;
  columns_sql text;
  values_sql text;
  conflict_sql text;
  stmt text;
BEGIN
  IF p_user_id IS NULL THEN
    RETURN;
  END IF;

  SELECT c.relkind
  INTO profiles_relkind
  FROM pg_class c
  JOIN pg_namespace n ON n.oid = c.relnamespace
  WHERE n.nspname = 'public'
    AND c.relname = 'profiles'
  LIMIT 1;

  IF profiles_relkind IS DISTINCT FROM 'r' THEN
    RETURN;
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name = 'id'
  ) INTO has_id;

  IF NOT has_id THEN
    RETURN;
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name = 'user_id'
  ) INTO has_user_id;

  SELECT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name = 'email'
  ) INTO has_email;

  SELECT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_schema = 'public' AND table_name = 'profiles' AND column_name = 'full_name'
  ) INTO has_full_name;

  columns_sql := 'id';
  values_sql := '$1';
  conflict_sql := '';

  IF has_user_id THEN
    columns_sql := columns_sql || ', user_id';
    values_sql := values_sql || ', $1';
  END IF;

  IF has_email THEN
    columns_sql := columns_sql || ', email';
    values_sql := values_sql || ', $2';
  END IF;

  IF has_full_name THEN
    columns_sql := columns_sql || ', full_name';
    values_sql := values_sql || ', COALESCE($3, $2, ''User'')';
    -- On conflict, update full_name if a new value is provided
    conflict_sql := 'SET full_name = COALESCE(EXCLUDED.full_name, profiles.full_name)';
  END IF;

  IF conflict_sql = '' THEN
    stmt := format(
      'INSERT INTO public.profiles (%s) VALUES (%s) ON CONFLICT (id) DO NOTHING',
      columns_sql,
      values_sql
    );
  ELSE
    stmt := format(
      'INSERT INTO public.profiles (%s) VALUES (%s) ON CONFLICT (id) DO UPDATE %s',
      columns_sql,
      values_sql,
      conflict_sql
    );
  END IF;

  EXECUTE stmt USING p_user_id, p_user_email, p_user_full_name;
END;
$_$;


ALTER FUNCTION "public"."ensure_profile_for_user"("p_user_id" "uuid", "p_user_email" "text", "p_user_full_name" "text") OWNER TO "postgres";

