-- Name: expire_pending_booking_requests(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."expire_pending_booking_requests"() RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  expired_count INTEGER;
BEGIN
  -- Update all pending requests that have passed their expiration time
  WITH expired AS (
    UPDATE session_bookings
    SET
      status = 'expired',
      updated_at = NOW()
    WHERE
      status = 'pending'
      AND expires_at IS NOT NULL
      AND expires_at < NOW()
    RETURNING id
  )
  SELECT COUNT(*) INTO expired_count FROM expired;

  RETURN expired_count;
END;
$$;


ALTER FUNCTION "public"."expire_pending_booking_requests"() OWNER TO "postgres";

