--
-- TOC entry 1567 (class 1255 OID 18775)
-- Name: find_nearby_regattas("extensions"."geography", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."find_nearby_regattas"("user_location" "extensions"."geography", "radius_km" integer DEFAULT 50) RETURNS TABLE("id" "uuid", "name" "text", "distance_km" numeric, "start_date" timestamp with time zone, "status" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    r.id,
    r.name,
    ROUND((ST_Distance(r.location, user_location) / 1000)::NUMERIC, 2) AS distance_km,
    r.start_date,
    r.status::TEXT
  FROM regattas r
  WHERE ST_DWithin(r.location, user_location, radius_km * 1000)
    AND r.status IN ('planned', 'active')
  ORDER BY ST_Distance(r.location, user_location);
END;
$$;


