--
-- TOC entry 1712 (class 1255 OID 172931)
-- Name: find_or_create_direct_thread("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."find_or_create_direct_thread"("other_user_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  current_user_id UUID;
  existing_thread_id UUID;
  new_thread_id UUID;
  other_user_name TEXT;
BEGIN
  -- Get current user
  current_user_id := auth.uid();
  IF current_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authenticated';
  END IF;

  -- Look for existing direct thread between these two users
  SELECT ct.id INTO existing_thread_id
  FROM crew_threads ct
  WHERE ct.thread_type = 'direct'
  AND EXISTS (
    SELECT 1 FROM crew_thread_members ctm1
    WHERE ctm1.thread_id = ct.id AND ctm1.user_id = current_user_id
  )
  AND EXISTS (
    SELECT 1 FROM crew_thread_members ctm2
    WHERE ctm2.thread_id = ct.id AND ctm2.user_id = other_user_id
  )
  AND (
    SELECT COUNT(*) FROM crew_thread_members WHERE thread_id = ct.id
  ) = 2
  LIMIT 1;

  -- Return existing thread if found
  IF existing_thread_id IS NOT NULL THEN
    RETURN existing_thread_id;
  END IF;

  -- Get other user's name for the thread
  SELECT full_name INTO other_user_name FROM profiles WHERE id = other_user_id;
  IF other_user_name IS NULL THEN
    other_user_name := 'Direct Message';
  END IF;

  -- Create new direct thread
  INSERT INTO crew_threads (name, owner_id, thread_type, avatar_emoji)
  VALUES (other_user_name, current_user_id, 'direct', '💬')
  RETURNING id INTO new_thread_id;

  -- Add both users as members
  INSERT INTO crew_thread_members (thread_id, user_id, role)
  VALUES
    (new_thread_id, current_user_id, 'owner'),
    (new_thread_id, other_user_id, 'member');

  RETURN new_thread_id;
END;
$$;


ALTER FUNCTION "public"."find_or_create_direct_thread"("other_user_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 1724 (class 1255 OID 175659)
-- Name: find_or_create_firebase_user("text", "text", "text", "text", "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."find_or_create_firebase_user"("p_firebase_uid" "text", "p_email" "text", "p_full_name" "text" DEFAULT NULL::"text", "p_avatar_url" "text" DEFAULT NULL::"text", "p_boat_class" "text" DEFAULT NULL::"text", "p_club_name" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("user_id" "uuid", "is_new_user" boolean, "supabase_user_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_supabase_user_id UUID;
  v_is_new BOOLEAN := false;
BEGIN
  -- First, try to find existing user by firebase_uid
  SELECT id INTO v_user_id
  FROM users
  WHERE firebase_uid = p_firebase_uid;

  IF v_user_id IS NOT NULL THEN
    -- Found by firebase_uid, return existing user
    RETURN QUERY SELECT v_user_id, false, v_user_id;
    RETURN;
  END IF;

  -- Try to find by email (existing RegattaFlow user)
  SELECT id INTO v_user_id
  FROM users
  WHERE LOWER(email) = LOWER(p_email);

  IF v_user_id IS NOT NULL THEN
    -- Link Firebase UID to existing user
    UPDATE users
    SET firebase_uid = p_firebase_uid,
        updated_at = now()
    WHERE id = v_user_id;

    RETURN QUERY SELECT v_user_id, false, v_user_id;
    RETURN;
  END IF;

  -- No existing user found, create new one
  -- Note: The actual Supabase auth.users entry will be created by the Edge Function
  -- This just creates the public.users profile entry
  v_is_new := true;

  -- We'll return NULL for user_id since the Edge Function will create the auth user
  RETURN QUERY SELECT NULL::UUID, true, NULL::UUID;
  RETURN;
END;
$$;


ALTER FUNCTION "public"."find_or_create_firebase_user"("p_firebase_uid" "text", "p_email" "text", "p_full_name" "text", "p_avatar_url" "text", "p_boat_class" "text", "p_club_name" "text", "p_metadata" "jsonb") OWNER TO "postgres";

