--
-- TOC entry 1679 (class 1255 OID 161046)
-- Name: find_race_participants("text", "date", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."find_race_participants"("race_name" "text", "race_date" "date", "race_venue" "text" DEFAULT NULL::"text", "exclude_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("regatta_id" "uuid", "user_id" "uuid", "user_name" "text", "avatar_emoji" "text", "avatar_color" "text", "has_prep_notes" boolean, "has_post_race_notes" boolean, "content_visibility" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    r.id AS regatta_id,
    r.created_by,
    p.full_name AS user_name,
    sp.avatar_emoji,
    sp.avatar_color,
    (r.prep_notes IS NOT NULL) AS has_prep_notes,
    (r.post_race_notes IS NOT NULL) AS has_post_race_notes,
    COALESCE(r.content_visibility, 'fleet')::TEXT AS content_visibility
  FROM regattas r
  JOIN profiles p ON p.id = r.created_by
  LEFT JOIN sailor_profiles sp ON sp.user_id = r.created_by
  WHERE
    LOWER(TRIM(r.name)) = LOWER(TRIM(race_name))
    AND r.start_date BETWEEN (race_date - INTERVAL '1 day') AND (race_date + INTERVAL '1 day')
    AND (exclude_user_id IS NULL OR r.created_by != exclude_user_id)
    -- Use profiles.allow_follower_sharing instead of sailor_profiles
    AND COALESCE(p.allow_follower_sharing, true) = true
  ORDER BY r.start_date ASC;
END;
$$;


ALTER FUNCTION "public"."find_race_participants"("race_name" "text", "race_date" "date", "race_venue" "text", "exclude_user_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 1716 (class 1255 OID 173346)
-- Name: generate_community_slug("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."generate_community_slug"("p_name" "text") RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_slug TEXT;
  v_suffix INTEGER := 0;
  v_final_slug TEXT;
BEGIN
  -- Convert to lowercase, replace spaces with hyphens, remove non-alphanumeric
  v_slug := lower(trim(p_name));
  v_slug := regexp_replace(v_slug, '[^a-z0-9\s-]', '', 'g');
  v_slug := regexp_replace(v_slug, '\s+', '-', 'g');
  v_slug := regexp_replace(v_slug, '-+', '-', 'g');
  v_slug := trim(both '-' from v_slug);

  -- Ensure uniqueness
  v_final_slug := v_slug;
  WHILE EXISTS (SELECT 1 FROM communities WHERE slug = v_final_slug) LOOP
    v_suffix := v_suffix + 1;
    v_final_slug := v_slug || '-' || v_suffix;
  END LOOP;

  RETURN v_final_slug;
END;
$$;


ALTER FUNCTION "public"."generate_community_slug"("p_name" "text") OWNER TO "postgres";

