-- TOC entry 1618 (class 1255 OID 68478)
-- Name: get_active_suggestions("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_active_suggestions"("p_user_id" "uuid", "p_limit" integer DEFAULT 50) RETURNS TABLE("id" "uuid", "suggestion_type" "text", "race_data" "jsonb", "confidence_score" numeric, "suggestion_reason" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        rsc.id,
        rsc.suggestion_type,
        rsc.race_data,
        rsc.confidence_score,
        rsc.suggestion_reason,
        rsc.created_at
    FROM public.race_suggestions_cache rsc
    WHERE rsc.user_id = p_user_id
        AND rsc.expires_at > NOW()
        AND rsc.dismissed_at IS NULL
        AND rsc.accepted_at IS NULL
    ORDER BY rsc.confidence_score DESC, rsc.created_at DESC
    LIMIT p_limit;
END;
$$;


