--
-- TOC entry 1683 (class 1255 OID 162354)
-- Name: get_author_venue_stats("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_author_venue_stats"("p_author_id" "uuid", "p_venue_id" "text") RETURNS TABLE("race_count" bigint, "avg_finish" numeric, "best_finish" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COUNT(*)::BIGINT as race_count,
    ROUND(AVG(rr.position)::NUMERIC, 1) as avg_finish,
    MIN(rr.position)::INTEGER as best_finish
  FROM race_results rr
  JOIN races r ON rr.race_id = r.id
  WHERE rr.sailor_id = p_author_id
  AND r.venue_id = p_venue_id
  AND rr.position IS NOT NULL;
END;
$$;


