-- TOC entry 1780 (class 1255 OID 225472)
-- Name: get_blueprint_access_info("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_blueprint_access_info"("p_slug" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_result jsonb;
BEGIN
  SELECT jsonb_build_object(
    'exists', true,
    'access_level', tb.access_level,
    'is_published', tb.is_published,
    'org_id', tb.organization_id,
    'org_name', o.name,
    'org_slug', o.slug,
    'title', tb.title,
    'price_cents', tb.price_cents,
    'currency', tb.currency
  )
  INTO v_result
  FROM timeline_blueprints tb
  LEFT JOIN organizations o ON o.id = tb.organization_id
  WHERE tb.slug = p_slug;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('exists', false);
  END IF;

  RETURN v_result;
END;
$$;


