--
-- TOC entry 1785 (class 1255 OID 225634)
-- Name: get_blueprint_subscriber_progress("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_blueprint_subscriber_progress"("p_blueprint_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_owner_id UUID;
  v_result JSONB;
BEGIN
  -- Verify the caller owns this blueprint
  SELECT user_id INTO v_owner_id
    FROM timeline_blueprints
   WHERE id = p_blueprint_id;

  IF v_owner_id IS NULL OR v_owner_id != auth.uid() THEN
    RAISE EXCEPTION 'Not authorized: you do not own this blueprint';
  END IF;

  SELECT COALESCE(jsonb_agg(row_data), '[]'::jsonb)
    INTO v_result
    FROM (
      SELECT jsonb_build_object(
        'subscriber_id', bs.subscriber_id,
        'name', COALESCE(p.full_name, 'Anonymous'),
        'avatar_url', p.avatar_url,
        'subscribed_at', bs.subscribed_at,
        'steps', COALESCE(
          (
            SELECT jsonb_agg(
              jsonb_build_object(
                'source_step_id', bsa.source_step_id,
                'adopted_step_id', bsa.adopted_step_id,
                'action', bsa.action,
                'status', COALESCE(ts.status, 'not_adopted'),
                'overall_rating', (ts.metadata -> 'review' ->> 'overall_rating')::int,
                'has_evidence', (ts.metadata -> 'act' -> 'media_urls') IS NOT NULL
                               AND jsonb_array_length(COALESCE(ts.metadata -> 'act' -> 'media_urls', '[]'::jsonb)) > 0,
                'step_title', COALESCE(ts.title, src.title)
              )
            )
            FROM blueprint_step_actions bsa
            LEFT JOIN timeline_steps ts ON ts.id = bsa.adopted_step_id
            LEFT JOIN timeline_steps src ON src.id = bsa.source_step_id
            WHERE bsa.subscription_id = bs.id
          ),
          '[]'::jsonb
        )
      ) AS row_data
      FROM blueprint_subscriptions bs
      JOIN profiles p ON p.id = bs.subscriber_id
      WHERE bs.blueprint_id = p_blueprint_id
      ORDER BY bs.subscribed_at DESC
    ) sub;

  RETURN v_result;
END;
$$;


ALTER FUNCTION "public"."get_blueprint_subscriber_progress"("p_blueprint_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 1791 (class 1255 OID 228105)
-- Name: get_class_experts("uuid", "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_class_experts"("target_class_id" "uuid", "exclude_user_id" "uuid" DEFAULT NULL::"uuid", "result_limit" integer DEFAULT 10) RETURNS TABLE("user_id" "uuid", "user_name" "text", "avatar_emoji" "text", "avatar_color" "text", "expert_score" integer, "podium_count" integer, "public_race_count" integer, "recent_activity" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  thirty_days_ago TIMESTAMP := NOW() - INTERVAL '30 days';
  ninety_days_ago TIMESTAMP := NOW() - INTERVAL '90 days';
BEGIN
  RETURN QUERY
  WITH user_boats AS (
    SELECT DISTINCT sb.user_id
    FROM sailor_boats sb
    WHERE sb.class_id = target_class_id
  ),
  sharing_users AS (
    -- Use profiles.allow_follower_sharing instead of sailor_profiles
    SELECT p.id AS user_id
    FROM profiles p
    WHERE p.id IN (SELECT user_boats.user_id FROM user_boats)
      AND COALESCE(p.allow_follower_sharing, true) = true
  ),
  race_scores AS (
    SELECT
      r.created_by AS user_id,
      COUNT(*) FILTER (WHERE rr.position <= 3) AS podium_finishes,
      COUNT(*) FILTER (WHERE rr.position <= 10) AS top_10_finishes,
      COUNT(*) AS total_races,
      MAX(r.created_at) AS last_race_date
    FROM regattas r
    JOIN race_results rr ON rr.regatta_id = r.id
    WHERE r.created_by IN (SELECT sharing_users.user_id FROM sharing_users)
    GROUP BY r.created_by
  ),
  sharing_scores AS (
    SELECT
      r.created_by AS user_id,
      COUNT(*) AS public_races,
      COUNT(*) FILTER (WHERE r.prep_notes IS NOT NULL) AS races_with_prep,
      COUNT(*) FILTER (WHERE r.post_race_notes IS NOT NULL) AS races_with_analysis,
      MAX(r.updated_at) AS last_share_date
    FROM regattas r
    WHERE r.created_by IN (SELECT sharing_users.user_id FROM sharing_users)
    GROUP BY r.created_by
  ),
  combined_scores AS (
    SELECT
      su.user_id,
      COALESCE(rs.podium_finishes, 0) * 10 +
      COALESCE(rs.top_10_finishes, 0) * 5 +
      COALESCE(rs.total_races, 0) * 3 +
      COALESCE(ss.public_races, 0) * 5 +
      COALESCE(ss.races_with_prep, 0) * 3 +
      COALESCE(ss.races_with_analysis, 0) * 3 AS base_score,
      COALESCE(rs.podium_finishes, 0) AS podiums,
      COALESCE(ss.public_races, 0) AS public_count,
      CASE
        WHEN GREATEST(COALESCE(rs.last_race_date, '1970-01-01'), COALESCE(ss.last_share_date, '1970-01-01')) > thirty_days_ago THEN 1.5
        WHEN GREATEST(COALESCE(rs.last_race_date, '1970-01-01'), COALESCE(ss.last_share_date, '1970-01-01')) > ninety_days_ago THEN 1.2
        ELSE 1.0
      END AS recency_mult,
      GREATEST(COALESCE(rs.last_race_date, '1970-01-01'), COALESCE(ss.last_share_date, '1970-01-01')) > thirty_days_ago AS is_recent
    FROM sharing_users su
    LEFT JOIN race_scores rs ON rs.user_id = su.user_id
    LEFT JOIN sharing_scores ss ON ss.user_id = su.user_id
    WHERE (exclude_user_id IS NULL OR su.user_id != exclude_user_id)
  )
  SELECT
    cs.user_id,
    p.full_name AS user_name,
    sp.avatar_emoji,
    sp.avatar_color,
    (cs.base_score * cs.recency_mult)::INT AS expert_score,
    cs.podiums AS podium_count,
    cs.public_count AS public_race_count,
    cs.is_recent AS recent_activity
  FROM combined_scores cs
  JOIN profiles p ON p.id = cs.user_id
  LEFT JOIN sailor_profiles sp ON sp.user_id = cs.user_id
  WHERE cs.base_score > 0
    AND p.full_name IS NOT NULL
  ORDER BY expert_score DESC
  LIMIT result_limit;
END;
$$;


ALTER FUNCTION "public"."get_class_experts"("target_class_id" "uuid", "exclude_user_id" "uuid", "result_limit" integer) OWNER TO "postgres";

