--
-- TOC entry 1689 (class 1255 OID 164806)
-- Name: get_community_races("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_community_races"("p_user_id" "uuid", "p_limit" integer DEFAULT 20) RETURNS TABLE("race_id" "uuid", "race_name" "text", "start_date" timestamp with time zone, "venue_name" "text", "race_type" "text", "community_count" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH user_clubs AS (
    SELECT club_id
    FROM public.club_members
    WHERE user_id = p_user_id
      AND is_active = true
  ),
  co_members AS (
    SELECT DISTINCT cm.user_id
    FROM public.club_members cm
    INNER JOIN user_clubs uc ON cm.club_id = uc.club_id
    WHERE cm.user_id != p_user_id
      AND cm.is_active = true
  )
  SELECT
    r.id AS race_id,
    r.name AS race_name,
    r.start_date,
    COALESCE(r.start_area_name, (r.metadata->>'venue_name')::TEXT) AS venue_name,
    r.race_type,
    COUNT(DISTINCT r.created_by) AS community_count
  FROM public.regattas r
  INNER JOIN co_members m ON r.created_by = m.user_id
  WHERE r.start_date >= NOW()
  GROUP BY r.id, r.name, r.start_date, r.start_area_name, r.metadata, r.race_type
  ORDER BY community_count DESC, r.start_date ASC
  LIMIT p_limit;
END;
$$;


ALTER FUNCTION "public"."get_community_races"("p_user_id" "uuid", "p_limit" integer) OWNER TO "postgres";

