--
-- TOC entry 1639 (class 1255 OID 136042)
-- Name: get_current_season("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_current_season"("p_user_id" "uuid") RETURNS TABLE("id" "uuid", "name" "text", "status" "text", "start_date" "date", "end_date" "date", "race_count" bigint, "completed_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id,
    s.name,
    s.status,
    s.start_date,
    s.end_date,
    (
      SELECT COUNT(*)
      FROM race_events re
      WHERE re.season_id = s.id AND re.user_id = p_user_id
    ) + (
      SELECT COUNT(*)
      FROM regatta_races rr
      JOIN season_regattas sr ON rr.regatta_id = sr.regatta_id
      WHERE sr.season_id = s.id
    ) AS race_count,
    (
      SELECT COUNT(*)
      FROM race_events re
      WHERE re.season_id = s.id
        AND re.user_id = p_user_id
        AND re.race_status = 'completed'
    ) + (
      SELECT COUNT(*)
      FROM regatta_races rr
      JOIN season_regattas sr ON rr.regatta_id = sr.regatta_id
      WHERE sr.season_id = s.id AND rr.status = 'completed'
    ) AS completed_count
  FROM seasons s
  WHERE s.user_id = p_user_id
    AND s.status = 'active'
  ORDER BY s.start_date DESC
  LIMIT 1;
END;
$$;


ALTER FUNCTION "public"."get_current_season"("p_user_id" "uuid") OWNER TO "postgres";

