--
-- TOC entry 1601 (class 1255 OID 50181)
-- Name: get_framework_trends("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_framework_trends"("sailor_uuid" "uuid", "limit_count" integer DEFAULT 10) RETURNS TABLE("race_date" timestamp with time zone, "puff_response_score" integer, "shift_awareness_score" integer, "tactics_score" integer, "downwind_detection_score" integer, "overall_score" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ra.created_at,
    CASE
      WHEN ra.upwind_puff_handling = 'traveler' THEN 5
      WHEN ra.upwind_puff_handling = 'mainsheet' THEN 3
      WHEN ra.upwind_puff_handling = 'feathered' THEN 1
      ELSE NULL
    END as puff_response_score,
    ra.upwind_shift_awareness,
    CASE
      WHEN 'delayed_tack' = ANY(ra.upwind_tactics_used) THEN 5
      WHEN array_length(ra.upwind_tactics_used, 1) > 0 THEN 3
      ELSE 1
    END as tactics_score,
    CASE
      WHEN ra.downwind_shift_detection = 'apparent_wind' THEN 5
      WHEN ra.downwind_shift_detection = 'compass' THEN 4
      WHEN ra.downwind_shift_detection = 'schooled_upwind_boats' THEN 3
      ELSE 1
    END as downwind_detection_score,
    ra.overall_satisfaction
  FROM race_analysis ra
  WHERE ra.sailor_id = sailor_uuid
  ORDER BY ra.created_at DESC
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION "public"."get_framework_trends"("sailor_uuid" "uuid", "limit_count" integer) OWNER TO "postgres";

