--
-- TOC entry 1599 (class 1255 OID 48505)
-- Name: get_map_bounds_for_racing_area("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_map_bounds_for_racing_area"("p_racing_area_name" "text" DEFAULT NULL::"text", "p_venue_id" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  bounds JSONB;
BEGIN
  IF p_racing_area_name IS NOT NULL THEN
    SELECT map_bounds INTO bounds
    FROM racing_area_aliases
    WHERE LOWER(racing_area_name) = LOWER(p_racing_area_name)
    LIMIT 1;

    IF bounds IS NOT NULL THEN
      UPDATE racing_area_aliases
      SET times_used = times_used + 1,
          last_used_at = NOW()
      WHERE LOWER(racing_area_name) = LOWER(p_racing_area_name);

      RETURN bounds;
    END IF;
  END IF;

  IF p_venue_id IS NOT NULL THEN
    SELECT map_bounds INTO bounds
    FROM sailing_venues
    WHERE id = p_venue_id
    AND map_bounds IS NOT NULL;

    IF bounds IS NOT NULL THEN
      RETURN bounds;
    END IF;
  END IF;

  RETURN '{
    "north": 22.35,
    "south": 22.20,
    "east": 114.35,
    "west": 114.05,
    "zoom_level": 11,
    "description": "Hong Kong waters - default view"
  }'::jsonb;
END;
$$;


