--
-- TOC entry 1613 (class 1255 OID 64533)
-- Name: get_onboarding_progress("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_onboarding_progress"("session_uuid" "uuid") RETURNS TABLE("total_suggestions" integer, "accepted_count" integer, "rejected_count" integer, "pending_count" integer, "edited_count" integer, "completion_percentage" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        COUNT(*)::INTEGER as total_suggestions,
        COUNT(*) FILTER (WHERE status = 'accepted')::INTEGER as accepted_count,
        COUNT(*) FILTER (WHERE status = 'rejected')::INTEGER as rejected_count,
        COUNT(*) FILTER (WHERE status = 'pending')::INTEGER as pending_count,
        COUNT(*) FILTER (WHERE status = 'edited')::INTEGER as edited_count,
        CASE
            WHEN COUNT(*) = 0 THEN 0
            ELSE ((COUNT(*) FILTER (WHERE status IN ('accepted', 'rejected', 'edited'))::FLOAT / COUNT(*)::FLOAT) * 100)::INTEGER
        END as completion_percentage
    FROM public.club_suggested_data
    WHERE session_id = session_uuid;
END;
$$;


