--
-- TOC entry 1753 (class 1255 OID 204496)
-- Name: get_organization_invite_by_token("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_organization_invite_by_token"("p_invite_token" "text") RETURNS "public"."organization_invites"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_token text := lower(trim(COALESCE(p_invite_token, '')));
  v_invite public.organization_invites;
BEGIN
  IF v_token = '' THEN
    RETURN NULL;
  END IF;

  SELECT *
  INTO v_invite
  FROM public.organization_invites oi
  WHERE lower(oi.invite_token) = v_token
  LIMIT 1;

  RETURN v_invite;
END;
$$;


