CREATE FUNCTION "public"."get_race_with_links"("race_id" "uuid") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_build_object(
    'race', row_to_json(r.*),
    'course', row_to_json(c.*),
    'boat', row_to_json(b.*),
    'boat_class', row_to_json(bc.*)
  ) INTO result
  FROM regattas r
  LEFT JOIN race_courses c ON r.course_id = c.id
  LEFT JOIN sailor_boats b ON r.boat_id = b.id
  LEFT JOIN boat_classes bc ON b.class_id = bc.id
  WHERE r.id = race_id;

  RETURN result;
END;
$$;


