-- Name: get_regatta_weather("extensions"."geography", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_regatta_weather"("regatta_location" "extensions"."geography", "time_range_hours" integer DEFAULT 24) RETURNS TABLE("wind_speed_knots" numeric, "wind_direction" numeric, "wave_height_meters" numeric, "weather_timestamp" timestamp with time zone, "distance_km" numeric)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    wc.wind_speed_knots,
    wc.wind_direction,
    wc.wave_height_meters,
    wc.timestamp,
    ROUND((ST_Distance(wc.location, regatta_location) / 1000)::NUMERIC, 2) AS distance_km
  FROM weather_conditions wc
  WHERE ST_DWithin(wc.location, regatta_location, 10000)
    AND wc.timestamp >= NOW() - INTERVAL '1 hour' * time_range_hours
  ORDER BY wc.timestamp DESC, ST_Distance(wc.location, regatta_location);
END;
$$;


