-- TOC entry 1608 (class 1255 OID 62607)
-- Name: get_sailor_coaching_overview("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_sailor_coaching_overview"("p_sailor_id" "uuid") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_build_object(
    'upcoming_sessions', (
      SELECT COALESCE(json_agg(row_to_json(cs)), '[]'::json)
      FROM coach_sailor_sessions_view cs
      WHERE cs.sailor_id = p_sailor_id
        AND cs.status IN ('scheduled', 'confirmed', 'pending')
        AND cs.scheduled_at >= NOW()
      ORDER BY cs.scheduled_at ASC
      LIMIT 10
    ),
    'completed_sessions', (
      SELECT COALESCE(json_agg(row_to_json(cs)), '[]'::json)
      FROM coach_sailor_sessions_view cs
      WHERE cs.sailor_id = p_sailor_id
        AND cs.status = 'completed'
      ORDER BY cs.completed_at DESC
      LIMIT 10
    )
  ) INTO result;
  RETURN result;
END;
$$;


