--
-- TOC entry 1640 (class 1255 OID 136043)
-- Name: get_season_summary("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_season_summary"("p_season_id" "uuid", "p_user_id" "uuid") RETURNS TABLE("season_id" "uuid", "season_name" "text", "status" "text", "total_races" bigint, "completed_races" bigint, "upcoming_races" bigint, "user_rank" integer, "user_points" numeric, "user_wins" integer, "results_sequence" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    s.id AS season_id,
    s.name AS season_name,
    s.status,
    (
      SELECT COUNT(*) FROM race_events re WHERE re.season_id = s.id
    ) + (
      SELECT COUNT(*) FROM regatta_races rr
      JOIN season_regattas sr ON rr.regatta_id = sr.regatta_id
      WHERE sr.season_id = s.id
    ) AS total_races,
    (
      SELECT COUNT(*) FROM race_events re
      WHERE re.season_id = s.id AND re.race_status = 'completed'
    ) + (
      SELECT COUNT(*) FROM regatta_races rr
      JOIN season_regattas sr ON rr.regatta_id = sr.regatta_id
      WHERE sr.season_id = s.id AND rr.status = 'completed'
    ) AS completed_races,
    (
      SELECT COUNT(*) FROM race_events re
      WHERE re.season_id = s.id AND re.race_status IN ('scheduled', 'upcoming')
    ) + (
      SELECT COUNT(*) FROM regatta_races rr
      JOIN season_regattas sr ON rr.regatta_id = sr.regatta_id
      WHERE sr.season_id = s.id AND rr.status = 'scheduled'
    ) AS upcoming_races,
    ss.rank AS user_rank,
    ss.net_points AS user_points,
    ss.wins AS user_wins,
    ss.race_results AS results_sequence
  FROM seasons s
  LEFT JOIN season_standings ss ON ss.season_id = s.id AND ss.user_id = p_user_id
  WHERE s.id = p_season_id;
END;
$$;


ALTER FUNCTION "public"."get_season_summary"("p_season_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 1788 (class 1255 OID 226793)
-- Name: get_suggested_next_steps("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_suggested_next_steps"("p_subscriber_id" "uuid", "p_interest_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("subscription_id" "uuid", "blueprint_id" "uuid", "blueprint_title" "text", "blueprint_slug" "text", "author_id" "uuid", "author_name" "text", "next_step_id" "uuid", "next_step_title" "text", "next_step_description" "text", "next_step_sort_order" integer, "total_steps" bigint, "adopted_count" bigint, "dismissed_count" bigint)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
  SELECT
    sub.id AS subscription_id,
    bp.id AS blueprint_id,
    bp.title AS blueprint_title,
    bp.slug AS blueprint_slug,
    bp.user_id AS author_id,
    p.full_name AS author_name,
    next_step.id AS next_step_id,
    next_step.title AS next_step_title,
    next_step.description AS next_step_description,
    next_step.sort_order AS next_step_sort_order,
    totals.total_steps,
    totals.adopted_count,
    totals.dismissed_count
  FROM blueprint_subscriptions sub
  JOIN timeline_blueprints bp ON bp.id = sub.blueprint_id AND bp.is_published = true
  LEFT JOIN profiles p ON p.id = bp.user_id
  CROSS JOIN LATERAL (
    SELECT
      COUNT(*) FILTER (WHERE TRUE) AS total_steps,
      COUNT(*) FILTER (WHERE bsa.action = 'adopted') AS adopted_count,
      COUNT(*) FILTER (WHERE bsa.action = 'dismissed') AS dismissed_count
    FROM timeline_steps ts
    LEFT JOIN blueprint_step_actions bsa
      ON bsa.subscription_id = sub.id AND bsa.source_step_id = ts.id
    WHERE ts.user_id = bp.user_id
      AND ts.interest_id = bp.interest_id
      AND ts.visibility != 'private'
  ) totals
  CROSS JOIN LATERAL (
    SELECT ts.id, ts.title, ts.description, ts.sort_order
    FROM timeline_steps ts
    WHERE ts.user_id = bp.user_id
      AND ts.interest_id = bp.interest_id
      AND ts.visibility != 'private'
      AND NOT EXISTS (
        SELECT 1 FROM blueprint_step_actions bsa
        WHERE bsa.subscription_id = sub.id
          AND bsa.source_step_id = ts.id
      )
    ORDER BY ts.sort_order ASC
    LIMIT 1
  ) next_step
  WHERE sub.subscriber_id = p_subscriber_id
    AND (p_interest_id IS NULL OR bp.interest_id = p_interest_id);
$$;


ALTER FUNCTION "public"."get_suggested_next_steps"("p_subscriber_id" "uuid", "p_interest_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 1703 (class 1255 OID 166647)
-- Name: get_training_plan_stats("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_training_plan_stats"("p_plan_id" "uuid") RETURNS TABLE("total_activities" integer, "completed_activities" integer, "total_duration" integer, "completed_duration" integer, "completion_percentage" numeric)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  SELECT
    COUNT(*)::INTEGER AS total_activities,
    COUNT(*) FILTER (WHERE is_completed = true)::INTEGER AS completed_activities,
    COALESCE(SUM(duration), 0)::INTEGER AS total_duration,
    COALESCE(SUM(duration) FILTER (WHERE is_completed = true), 0)::INTEGER AS completed_duration,
    CASE
      WHEN COUNT(*) > 0 THEN
        ROUND((COUNT(*) FILTER (WHERE is_completed = true)::NUMERIC / COUNT(*)::NUMERIC) * 100, 1)
      ELSE 0
    END AS completion_percentage
  FROM training_activities
  WHERE plan_id = p_plan_id;
$$;


