--
-- TOC entry 1571 (class 1255 OID 18889)
-- Name: get_user_ai_stats("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_user_ai_stats"("p_user_id" "uuid", "p_days" integer DEFAULT 30) RETURNS TABLE("function_name" "text", "total_requests" integer, "successful_requests" integer, "total_tokens" integer, "avg_processing_time" numeric, "last_used" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    aul.function_name,
    COUNT(*)::INTEGER as total_requests,
    SUM(CASE WHEN aul.success THEN 1 ELSE 0 END)::INTEGER as successful_requests,
    SUM(aul.tokens_used)::INTEGER as total_tokens,
    ROUND(AVG(aul.processing_time_ms)::NUMERIC, 2) as avg_processing_time,
    MAX(aul.created_at) as last_used
  FROM ai_usage_logs aul
  WHERE aul.user_id = p_user_id
    AND aul.created_at >= NOW() - INTERVAL '1 day' * p_days
  GROUP BY aul.function_name
  ORDER BY total_requests DESC;
END;
$$;


ALTER FUNCTION "public"."get_user_ai_stats"("p_user_id" "uuid", "p_days" integer) OWNER TO "postgres";

