--
-- TOC entry 1745 (class 1255 OID 202794)
-- Name: has_org_role("uuid", "text"[], "uuid", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."has_org_role"("p_org_id" "uuid", "p_roles" "text"[], "p_user_id" "uuid" DEFAULT "auth"."uid"(), "p_require_verified" boolean DEFAULT false) RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.organization_memberships om
    WHERE om.organization_id = p_org_id
      AND om.user_id = p_user_id
      AND om.status IN ('active', 'verified')
      AND (
        NOT p_require_verified
        OR om.is_verified = true
        OR om.status = 'verified'
      )
      AND (
        p_roles IS NULL
        OR array_length(p_roles, 1) IS NULL
        OR om.role = ANY (p_roles)
      )
  );
$$;


ALTER FUNCTION "public"."has_org_role"("p_org_id" "uuid", "p_roles" "text"[], "p_user_id" "uuid", "p_require_verified" boolean) OWNER TO "postgres";

