-- TOC entry 1738 (class 1255 OID 191837)
-- Name: increment_unread_count("uuid", "uuid", timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."increment_unread_count"("p_conversation_id" "uuid", "p_sender_id" "uuid", "p_last_message_at" timestamp with time zone, "p_last_message_preview" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
BEGIN
  UPDATE coaching_conversations
  SET
    last_message_at = p_last_message_at,
    last_message_preview = p_last_message_preview,
    coach_unread_count = CASE
      WHEN p_sender_id = sailor_id THEN coach_unread_count + 1
      ELSE coach_unread_count
    END,
    sailor_unread_count = CASE
      WHEN p_sender_id = coach_id THEN sailor_unread_count + 1
      ELSE sailor_unread_count
    END
  WHERE id = p_conversation_id;
END;
$$;


ALTER FUNCTION "public"."increment_unread_count"("p_conversation_id" "uuid", "p_sender_id" "uuid", "p_last_message_at" timestamp with time zone, "p_last_message_preview" "text") OWNER TO "postgres";

--
-- TOC entry 1664 (class 1255 OID 140602)
-- Name: insert_sample_coach_annotations(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."insert_sample_coach_annotations"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  coach_profile_id uuid := 'd6c95c89-43e6-4d69-8f2c-58d392c22d16'; -- Sarah Chen mock coach
BEGIN
  -- Only trigger for sample data with completed status
  IF NEW.metadata->>'is_sample' = 'true' AND NEW.status = 'completed' THEN
    -- Check if coach profile exists
    IF EXISTS (SELECT 1 FROM profiles WHERE id = coach_profile_id) THEN
      -- Insert sample annotations
      INSERT INTO coach_race_annotations (race_id, coach_id, sailor_id, field, comment, is_read)
      VALUES
        (NEW.id, coach_profile_id, NEW.created_by, 'result',
         'Excellent result! Top 3 in this fleet is a significant achievement. Keep building on this momentum.', true),
        (NEW.id, coach_profile_id, NEW.created_by, 'keyMoment',
         'Great awareness on that wave set. This kind of observation comes from experience - you''re developing good downwind instincts.', true),
        (NEW.id, coach_profile_id, NEW.created_by, 'start',
         'Your start execution has really improved. The boat end choice showed good pre-race analysis of the wind patterns.', false),
        (NEW.id, coach_profile_id, NEW.created_by, 'upwind',
         'Staying in phase with shifts is one of the most important skills - you''re clearly getting better at reading the wind.', true);
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."insert_sample_coach_annotations"() OWNER TO "postgres";

