--
-- TOC entry 1680 (class 1255 OID 162351)
-- Name: is_venue_member("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."is_venue_member"("p_user_id" "uuid", "p_venue_id" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Check saved_venues
  IF EXISTS (
    SELECT 1 FROM saved_venues
    WHERE user_id = p_user_id AND venue_id = p_venue_id
  ) THEN
    RETURN true;
  END IF;

  -- Check member roles
  IF EXISTS (
    SELECT 1 FROM venue_member_roles
    WHERE user_id = p_user_id AND venue_id = p_venue_id
  ) THEN
    RETURN true;
  END IF;

  -- For now, allow all authenticated users to post
  -- (race_results check can be added when that join is available)
  IF p_user_id IS NOT NULL THEN
    RETURN true;
  END IF;

  RETURN false;
END;
$$;


