--
-- TOC entry 1656 (class 1255 OID 138066)
-- Name: join_practice_by_invite("text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."join_practice_by_invite"("p_invite_code" "text", "p_display_name" "text" DEFAULT NULL::"text", "p_role" "text" DEFAULT 'crew'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_session_id UUID;
  v_new_member_id UUID;
BEGIN
  -- Find session by invite code
  SELECT id INTO v_session_id
  FROM practice_sessions
  WHERE invite_code = p_invite_code;

  IF v_session_id IS NULL THEN
    RAISE EXCEPTION 'Invalid invite code';
  END IF;

  -- Check if user is already a member
  IF EXISTS (
    SELECT 1 FROM practice_session_members
    WHERE session_id = v_session_id
    AND user_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'Already a member of this practice session';
  END IF;

  -- Add user as member
  INSERT INTO practice_session_members (session_id, user_id, display_name, role, rsvp_status)
  VALUES (v_session_id, auth.uid(), p_display_name, p_role, 'accepted')
  RETURNING id INTO v_new_member_id;

  RETURN v_new_member_id;
END;
$$;


ALTER FUNCTION "public"."join_practice_by_invite"("p_invite_code" "text", "p_display_name" "text", "p_role" "text") OWNER TO "postgres";

--
-- TOC entry 1675 (class 1255 OID 154899)
-- Name: join_race_by_invite_code("text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."join_race_by_invite_code"("p_invite_code" "text", "p_display_name" "text" DEFAULT NULL::"text", "p_role" "text" DEFAULT NULL::"text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_collaborator race_collaborators%ROWTYPE;
  v_user_id UUID := auth.uid();
BEGIN
  IF v_user_id IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Not authenticated');
  END IF;

  -- Find collaborator record with this invite code
  SELECT * INTO v_collaborator
  FROM race_collaborators
  WHERE invite_code = UPPER(p_invite_code)
    AND status = 'pending';

  IF v_collaborator IS NULL THEN
    RETURN json_build_object('success', false, 'error', 'Invalid or expired invite code');
  END IF;

  -- Check if user is already a collaborator on this race
  IF EXISTS (
    SELECT 1 FROM race_collaborators
    WHERE regatta_id = v_collaborator.regatta_id
    AND user_id = v_user_id
  ) THEN
    RETURN json_build_object('success', false, 'error', 'Already a collaborator on this race');
  END IF;

  -- Update the collaborator record with the joining user
  UPDATE race_collaborators
  SET user_id = v_user_id,
      display_name = COALESCE(p_display_name, display_name),
      role = COALESCE(p_role, role),
      status = 'accepted',
      joined_at = NOW(),
      invite_code = NULL  -- Clear invite code after use
  WHERE id = v_collaborator.id;

  RETURN json_build_object(
    'success', true,
    'regatta_id', v_collaborator.regatta_id,
    'collaborator_id', v_collaborator.id
  );
END;
$$;


ALTER FUNCTION "public"."join_race_by_invite_code"("p_invite_code" "text", "p_display_name" "text", "p_role" "text") OWNER TO "postgres";

