--
-- TOC entry 1737 (class 1255 OID 190662)
-- Name: mark_expiration_warnings(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."mark_expiration_warnings"() RETURNS integer
    LANGUAGE "plpgsql"
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  warning_count INTEGER;
BEGIN
  -- Mark requests that expire within 24 hours and haven't been warned
  WITH warned AS (
    UPDATE session_bookings
    SET
      expiration_warning_sent = TRUE,
      updated_at = NOW()
    WHERE
      status = 'pending'
      AND expiration_warning_sent = FALSE
      AND expires_at IS NOT NULL
      AND expires_at < NOW() + INTERVAL '24 hours'
      AND expires_at > NOW()
    RETURNING id, coach_id, sailor_id
  )
  SELECT COUNT(*) INTO warning_count FROM warned;

  RETURN warning_count;
END;
$$;


ALTER FUNCTION "public"."mark_expiration_warnings"() OWNER TO "postgres";

