--
-- TOC entry 1754 (class 1255 OID 204497)
-- Name: mark_organization_invite_opened("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."mark_organization_invite_opened"("p_invite_token" "text") RETURNS "public"."organization_invites"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_token text := lower(trim(COALESCE(p_invite_token, '')));
  v_invite public.organization_invites;
BEGIN
  IF v_token = '' THEN
    RETURN NULL;
  END IF;

  UPDATE public.organization_invites oi
  SET
    status = 'opened',
    responded_at = COALESCE(oi.responded_at, now())
  WHERE lower(oi.invite_token) = v_token
    AND oi.status IN ('draft', 'sent')
  RETURNING *
  INTO v_invite;

  IF v_invite.id IS NOT NULL THEN
    RETURN v_invite;
  END IF;

  RETURN public.get_organization_invite_by_token(v_token);
END;
$$;


ALTER FUNCTION "public"."mark_organization_invite_opened"("p_invite_token" "text") OWNER TO "postgres";

--
-- TOC entry 1821 (class 1255 OID 245576)
-- Name: mark_step_active("uuid", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."mark_step_active"("p_step_id" "uuid", "p_source" "text", "p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_jwt_role text := COALESCE(
    current_setting('request.jwt.claims', true)::jsonb->>'role',
    ''
  );
  v_user_id uuid;
  v_owns    boolean;
BEGIN
  IF p_source NOT IN ('telegram', 'whatsapp', 'voice', 'in_app', 'web', 'sms') THEN
    RAISE EXCEPTION 'mark_step_active: invalid source %', p_source USING ERRCODE = '22023';
  END IF;

  IF v_jwt_role = 'service_role' THEN
    IF p_user_id IS NULL THEN
      RAISE EXCEPTION 'mark_step_active: service_role caller must pass p_user_id'
        USING ERRCODE = '22023';
    END IF;
    v_user_id := p_user_id;
  ELSE
    v_user_id := auth.uid();
    IF v_user_id IS NULL THEN
      RAISE EXCEPTION 'mark_step_active: not authenticated' USING ERRCODE = '42501';
    END IF;
    IF p_user_id IS NOT NULL AND p_user_id <> v_user_id THEN
      RAISE EXCEPTION 'mark_step_active: cannot specify p_user_id as non-service caller'
        USING ERRCODE = '42501';
    END IF;
  END IF;

  SELECT EXISTS (
    SELECT 1
    FROM public.timeline_steps
    WHERE id = p_step_id AND user_id = v_user_id
  ) INTO v_owns;

  IF NOT v_owns THEN
    RETURN;
  END IF;

  INSERT INTO public.step_recent_activity (user_id, step_id, last_active_at, source)
  VALUES (v_user_id, p_step_id, now(), p_source)
  ON CONFLICT (user_id, step_id)
  DO UPDATE SET
    last_active_at = EXCLUDED.last_active_at,
    source         = EXCLUDED.source;
END;
$$;


ALTER FUNCTION "public"."mark_step_active"("p_step_id" "uuid", "p_source" "text", "p_user_id" "uuid") OWNER TO "postgres";

--
-- TOC entry 12495 (class 0 OID 0)
-- Dependencies: 1821
-- Name: FUNCTION "mark_step_active"("p_step_id" "uuid", "p_source" "text", "p_user_id" "uuid"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."mark_step_active"("p_step_id" "uuid", "p_source" "text", "p_user_id" "uuid") IS 'UPSERTs (user_id, p_step_id) into step_recent_activity with last_active_at = now(). For service_role callers (bot webhooks) p_user_id is required and trusted. For authenticated end-user callers p_user_id must be NULL or equal auth.uid(). Silently no-ops if the resolved user does not own the step.';


--
-- TOC entry 1778 (class 1255 OID 224348)
-- Name: notify_blueprint_subscribers(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_blueprint_subscribers"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
BEGIN
  IF NEW.visibility != 'private' THEN
    INSERT INTO social_notifications (user_id, type, title, body, actor_id, data, created_at)
    SELECT
      bs.subscriber_id,
      'blueprint_new_step',
      'New step in ' || tb.title,
      COALESCE(NEW.title, 'Untitled step'),
      NEW.user_id,
      jsonb_build_object(
        'step_id', NEW.id,
        'step_title', NEW.title,
        'blueprint_id', tb.id,
        'blueprint_title', tb.title,
        'author_id', NEW.user_id
      ),
      now()
    FROM timeline_blueprints tb
    JOIN blueprint_subscriptions bs ON bs.blueprint_id = tb.id
    JOIN blueprint_steps bst ON bst.blueprint_id = tb.id AND bst.step_id = NEW.id
    WHERE tb.user_id = NEW.user_id
      AND tb.is_published = true;
  END IF;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_blueprint_subscribers"() OWNER TO "postgres";

--
-- TOC entry 1818 (class 1255 OID 245190)
-- Name: notify_discuss_reply(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_discuss_reply"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  notify_url text;
  trigger_secret text;
BEGIN
  SELECT decrypted_secret INTO notify_url
    FROM vault.decrypted_secrets
    WHERE name = 'discuss_notify_url'
    LIMIT 1;

  SELECT decrypted_secret INTO trigger_secret
    FROM vault.decrypted_secrets
    WHERE name = 'discuss_trigger_secret'
    LIMIT 1;

  IF notify_url IS NULL OR notify_url = '' THEN
    RETURN NEW;
  END IF;

  PERFORM net.http_post(
    url := notify_url,
    headers := jsonb_build_object(
      'content-type', 'application/json',
      'x-discuss-trigger-secret', COALESCE(trigger_secret, '')
    ),
    body := jsonb_build_object(
      'commentId', NEW.id,
      'discussionId', NEW.discussion_id,
      'authorId', NEW.author_id,
      'body', NEW.body
    )
  );

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE NOTICE '[discuss-reply-notify] http_post failed: %', SQLERRM;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_discuss_reply"() OWNER TO "postgres";

--
-- TOC entry 1775 (class 1255 OID 217297)
-- Name: notify_followers_on_step_completed(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_followers_on_step_completed"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor_name TEXT;
  v_follower RECORD;
BEGIN
  -- Only fire when status changes to 'completed'
  IF OLD.status = 'completed' OR NEW.status != 'completed' THEN
    RETURN NEW;
  END IF;

  -- Get the actor's name
  SELECT full_name INTO v_actor_name
  FROM profiles
  WHERE id = NEW.user_id;

  -- Notify each follower who has notifications enabled
  FOR v_follower IN
    SELECT follower_id
    FROM user_follows
    WHERE following_id = NEW.user_id
      AND is_muted = false
  LOOP
    INSERT INTO social_notifications (user_id, type, actor_id, title, body, data)
    VALUES (
      v_follower.follower_id,
      'followed_user_step_completed',
      NEW.user_id,
      COALESCE(v_actor_name, 'Someone') || ' completed a step',
      NEW.title,
      jsonb_build_object(
        'step_id', NEW.id,
        'interest_id', NEW.interest_id,
        'category', NEW.category
      )
    );
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_followers_on_step_completed"() OWNER TO "postgres";

--
-- TOC entry 1729 (class 1255 OID 179367)
-- Name: notify_on_activity_comment(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_on_activity_comment"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor_name TEXT;
BEGIN
  -- Don't notify if user is commenting on their own activity
  IF NEW.user_id = NEW.target_user_id THEN
    RETURN NEW;
  END IF;

  -- Get commenter's name
  SELECT full_name INTO v_actor_name
  FROM profiles
  WHERE id = NEW.user_id;

  -- Create a notification for the target user using correct columns
  INSERT INTO social_notifications (
    user_id,
    type,
    actor_id,
    title,
    body,
    data
  ) VALUES (
    NEW.target_user_id,
    'race_comment',  -- Use existing enum value that's similar
    NEW.user_id,
    COALESCE(v_actor_name, 'Someone') || ' commented on your activity',
    LEFT(NEW.content, 100),
    jsonb_build_object(
      'activity_type', NEW.activity_type,
      'activity_id', NEW.activity_id,
      'comment_id', NEW.id
    )
  );

  RETURN NEW;
EXCEPTION WHEN others THEN
  -- Don't fail the comment insert if notification fails
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_on_activity_comment"() OWNER TO "postgres";

--
-- TOC entry 1765 (class 1255 OID 206809)
-- Name: notify_on_org_membership_activated(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_on_org_membership_activated"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_should_notify boolean := false;
  v_org_name text := 'your organization';
  v_inviter_id uuid := NULL;
  v_invite_id uuid := NULL;
BEGIN
  IF NEW.user_id IS NULL OR NEW.organization_id IS NULL THEN
    RETURN NEW;
  END IF;

  IF TG_OP = 'INSERT' THEN
    v_should_notify := NEW.status IN ('active', 'verified');
  ELSIF TG_OP = 'UPDATE' THEN
    v_should_notify :=
      NEW.status IN ('active', 'verified')
      AND COALESCE(OLD.status, '') NOT IN ('active', 'verified');
  END IF;

  IF NOT v_should_notify THEN
    RETURN NEW;
  END IF;

  SELECT o.name
  INTO v_org_name
  FROM public.organizations o
  WHERE o.id = NEW.organization_id;

  BEGIN
    IF NEW.metadata ? 'accepted_invite_id' THEN
      v_invite_id := (NEW.metadata ->> 'accepted_invite_id')::uuid;
    END IF;
  EXCEPTION
    WHEN others THEN
      v_invite_id := NULL;
  END;

  IF v_invite_id IS NOT NULL THEN
    SELECT oi.invited_by
    INTO v_inviter_id
    FROM public.organization_invites oi
    WHERE oi.id = v_invite_id;
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.social_notifications sn
    WHERE sn.user_id = NEW.user_id
      AND sn.type = 'organization_joined'
      AND COALESCE(sn.data ->> 'organization_id', '') = NEW.organization_id::text
      AND sn.created_at >= now() - interval '24 hours'
  ) THEN
    INSERT INTO public.social_notifications (
      user_id,
      type,
      actor_id,
      title,
      body,
      data
    )
    VALUES (
      NEW.user_id,
      'organization_joined',
      v_inviter_id,
      'Welcome to ' || COALESCE(v_org_name, 'your organization'),
      'Your organization access is now active.',
      jsonb_build_object(
        'organization_id', NEW.organization_id,
        'role', NEW.role,
        'status', NEW.status
      )
    );
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_on_org_membership_activated"() OWNER TO "postgres";

--
-- TOC entry 1767 (class 1255 OID 210353)
-- Name: notify_org_membership_decision("uuid", "uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_org_membership_decision"("p_target_user_id" "uuid", "p_organization_id" "uuid", "p_organization_name" "text", "p_decision" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_type public.social_notification_type;
  v_title text;
  v_body text;
  v_notification_id uuid;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  IF p_decision NOT IN ('approved', 'rejected') THEN
    RAISE EXCEPTION 'Invalid decision';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.organization_memberships om
    WHERE om.organization_id = p_organization_id
      AND om.user_id = auth.uid()
      AND om.role IN ('admin', 'manager')
      AND COALESCE(om.membership_status, om.status) = 'active'
  ) THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  IF p_decision = 'approved' THEN
    v_type := 'org_membership_approved';
    v_title := 'Membership approved';
    v_body := format('Your request to join %s was approved.', COALESCE(NULLIF(p_organization_name, ''), 'this organization'));
  ELSE
    v_type := 'org_membership_rejected';
    v_title := 'Membership request update';
    v_body := format('Your request to join %s was not approved.', COALESCE(NULLIF(p_organization_name, ''), 'this organization'));
  END IF;

  INSERT INTO public.social_notifications (
    user_id,
    type,
    title,
    body,
    data
  ) VALUES (
    p_target_user_id,
    v_type,
    v_title,
    v_body,
    jsonb_build_object(
      'organization_id', p_organization_id,
      'organization_name', p_organization_name,
      'decision', p_decision
    )
  )
  RETURNING id INTO v_notification_id;

  RETURN v_notification_id;
END;
$$;


ALTER FUNCTION "public"."notify_org_membership_decision"("p_target_user_id" "uuid", "p_organization_id" "uuid", "p_organization_name" "text", "p_decision" "text") OWNER TO "postgres";

--
-- TOC entry 1723 (class 1255 OID 173414)
-- Name: notify_thread_members_on_message(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."notify_thread_members_on_message"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_sender_name TEXT;
  v_thread_name TEXT;
  v_thread_type TEXT;
  v_member RECORD;
BEGIN
  -- Skip system messages
  IF NEW.message_type = 'system' THEN
    RETURN NEW;
  END IF;

  -- Get sender info
  SELECT full_name INTO v_sender_name
  FROM profiles
  WHERE id = NEW.user_id;

  -- Get thread info
  SELECT name, thread_type INTO v_thread_name, v_thread_type
  FROM crew_threads
  WHERE id = NEW.thread_id;

  -- Create in-app notifications for all other thread members
  FOR v_member IN
    SELECT ctm.user_id
    FROM crew_thread_members ctm
    WHERE ctm.thread_id = NEW.thread_id
    AND ctm.user_id != NEW.user_id
    AND ctm.is_active = true
  LOOP
    INSERT INTO social_notifications (
      user_id,
      type,
      actor_id,
      title,
      body,
      data
    )
    VALUES (
      v_member.user_id,
      'new_message',
      NEW.user_id,
      CASE
        WHEN v_thread_type = 'direct' THEN COALESCE(v_sender_name, 'Someone')
        ELSE COALESCE(v_thread_name, 'Group Chat')
      END,
      LEFT(NEW.message, 100),
      jsonb_build_object(
        'thread_id', NEW.thread_id,
        'message_id', NEW.id,
        'thread_type', v_thread_type
      )
    );
  END LOOP;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."notify_thread_members_on_message"() OWNER TO "postgres";

