--
-- TOC entry 1734 (class 1255 OID 190651)
-- Name: record_coach_pricing_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."record_coach_pricing_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
BEGIN
  -- Only record if pricing-related fields changed
  IF (
    OLD.hourly_rate IS DISTINCT FROM NEW.hourly_rate OR
    OLD.currency IS DISTINCT FROM NEW.currency OR
    OLD.session_type_rates IS DISTINCT FROM NEW.session_type_rates OR
    OLD.custom_charges IS DISTINCT FROM NEW.custom_charges OR
    OLD.session_durations IS DISTINCT FROM NEW.session_durations OR
    OLD.package_pricing IS DISTINCT FROM NEW.package_pricing
  ) THEN
    NEW.pricing_history = COALESCE(NEW.pricing_history, '[]'::jsonb) || jsonb_build_object(
      'changed_at', NOW(),
      'hourly_rate', NEW.hourly_rate,
      'currency', NEW.currency,
      'session_type_rates', NEW.session_type_rates,
      'custom_charges', NEW.custom_charges,
      'session_durations', NEW.session_durations,
      'package_pricing', NEW.package_pricing,
      'previous_hourly_rate', OLD.hourly_rate,
      'previous_currency', OLD.currency
    );
  END IF;

  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."record_coach_pricing_change"() OWNER TO "postgres";

--
-- TOC entry 1619 (class 1255 OID 68479)
-- Name: record_suggestion_feedback("uuid", "uuid", "text", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."record_suggestion_feedback"("p_user_id" "uuid", "p_suggestion_id" "uuid", "p_action" "text", "p_modified_fields" "text"[] DEFAULT NULL::"text"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_feedback_id UUID;
    v_suggestion RECORD;
BEGIN
    SELECT suggestion_type, confidence_score
    INTO v_suggestion
    FROM public.race_suggestions_cache
    WHERE id = p_suggestion_id;

    INSERT INTO public.suggestion_feedback (
        user_id,
        suggestion_id,
        action,
        suggestion_type,
        confidence_score,
        modified_fields
    )
    VALUES (
        p_user_id,
        p_suggestion_id,
        p_action,
        v_suggestion.suggestion_type,
        v_suggestion.confidence_score,
        p_modified_fields
    )
    RETURNING id INTO v_feedback_id;

    IF p_action = 'accepted' THEN
        UPDATE public.race_suggestions_cache
        SET accepted_at = NOW()
        WHERE id = p_suggestion_id;
    ELSIF p_action = 'dismissed' THEN
        UPDATE public.race_suggestions_cache
        SET dismissed_at = NOW()
        WHERE id = p_suggestion_id;
    END IF;

    RETURN v_feedback_id;
END;
$$;


ALTER FUNCTION "public"."record_suggestion_feedback"("p_user_id" "uuid", "p_suggestion_id" "uuid", "p_action" "text", "p_modified_fields" "text"[]) OWNER TO "postgres";

