CREATE FUNCTION "public"."refresh_timeline_events"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ begin   truncate table public.timeline_events;    insert into public.timeline_events (id, title, start_time, status, location, summary, domain_id)   select     r.id,     r.name as title,     coalesce(       case         when r.event_date is not null then (r.event_date::timestamp + coalesce(r.start_time, time '00:00')) at time zone 'UTC'         else null       end,       reg.start_date,       reg.created_at     ) as start_time,     coalesce(r.status, 'planned') as status,     coalesce(reg.start_area_name, reg.course_area_designation, reg.name) as location,     coalesce(reg.start_strategy, reg.strategy_status, 'Race prep in progress') as summary,     'yachtracing'::text as domain_id   from public.race_events r   left join public.regattas reg on reg.id = r.regatta_id    union all    select     cs.id,     cs.scenario_title as title,     cs.scheduled_start as start_time,     coalesce(cs.status, 'scheduled') as status,     cs.unit_name as location,     coalesce(cs.learning_focus, cs.notes) as summary,     coalesce(cs.domain_id, 'nursing') as domain_id   from public.clinical_sessions cs; end; $$;


