-- TOC entry 1720 (class 1255 OID 173411)
-- Name: register_push_token("text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."register_push_token"("p_token" "text", "p_platform" "text", "p_device_name" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_token_id UUID;
BEGIN
  -- Upsert the token
  INSERT INTO push_tokens (user_id, token, platform, device_name, last_used_at)
  VALUES (auth.uid(), p_token, p_platform, p_device_name, NOW())
  ON CONFLICT (user_id, token)
  DO UPDATE SET
    platform = EXCLUDED.platform,
    device_name = EXCLUDED.device_name,
    last_used_at = NOW()
  RETURNING id INTO v_token_id;

  RETURN v_token_id;
END;
$$;


