-- TOC entry 1590 (class 1255 OID 31889)
-- Name: reject_booking("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."reject_booking"("p_booking_id" "uuid", "p_coach_user_id" "uuid", "p_response" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_coach_id UUID;
BEGIN
  SELECT id INTO v_coach_id
  FROM public.coach_profiles
  WHERE user_id = p_coach_user_id;

  IF v_coach_id IS NULL THEN
    RAISE EXCEPTION 'Coach profile not found';
  END IF;

  UPDATE public.session_bookings
  SET
    status = 'rejected',
    coach_response = p_response,
    updated_at = NOW()
  WHERE id = p_booking_id
    AND coach_id = v_coach_id
    AND status = 'pending';

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Booking not found or already processed';
  END IF;
END;
$$;


