--
-- TOC entry 1764 (class 1255 OID 206806)
-- Name: remove_organization_member("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."remove_organization_member"("p_organization_id" "uuid", "p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actor_id uuid := auth.uid();
  v_rows_updated integer := 0;
BEGIN
  IF v_actor_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required.';
  END IF;

  IF p_organization_id IS NULL OR p_user_id IS NULL THEN
    RAISE EXCEPTION 'Organization and user are required.';
  END IF;

  IF v_actor_id = p_user_id THEN
    RAISE EXCEPTION 'Cannot remove your own membership with this action.';
  END IF;

  IF NOT public.has_org_role(
    p_organization_id,
    ARRAY['owner', 'admin', 'manager']::text[]
  ) THEN
    RAISE EXCEPTION 'Insufficient privileges to remove member.';
  END IF;

  UPDATE public.organization_memberships om
  SET
    status = 'inactive',
    is_verified = false,
    verification_source = NULL,
    updated_at = now(),
    metadata = COALESCE(om.metadata, '{}'::jsonb) || jsonb_build_object(
      'removed_at', now(),
      'removed_by', v_actor_id
    )
  WHERE om.organization_id = p_organization_id
    AND om.user_id = p_user_id
    AND om.status IN ('active', 'verified', 'pending', 'invited');

  GET DIAGNOSTICS v_rows_updated = ROW_COUNT;

  RETURN v_rows_updated > 0;
END;
$$;


ALTER FUNCTION "public"."remove_organization_member"("p_organization_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

