--
-- TOC entry 1826 (class 1255 OID 245666)
-- Name: resolve_share_token("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."resolve_share_token"("p_token" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_row public.share_tokens%ROWTYPE;
  v_now TIMESTAMPTZ := now();
  v_window_seconds CONSTANT INTEGER := 60;
  v_window_max CONSTANT INTEGER := 120;
  v_payload JSONB;
BEGIN
  SELECT * INTO v_row
  FROM public.share_tokens
  WHERE token = p_token
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN NULL;
  END IF;

  IF v_row.revoked_at IS NOT NULL THEN
    RETURN jsonb_build_object('error', 'revoked');
  END IF;

  IF v_row.expires_at IS NOT NULL AND v_row.expires_at < v_now THEN
    RETURN jsonb_build_object('error', 'expired');
  END IF;

  IF v_row.rate_window_started_at IS NULL
    OR v_row.rate_window_started_at < v_now - make_interval(secs => v_window_seconds) THEN
    v_row.rate_window_started_at := v_now;
    v_row.rate_window_count := 0;
  END IF;

  IF v_row.rate_window_count >= v_window_max THEN
    RAISE LOG 'share_tokens: rate limit hit for token %', v_row.id;
    RETURN jsonb_build_object('error', 'rate_limited');
  END IF;

  IF v_row.target_type = 'step' THEN
    SELECT jsonb_build_object(
      'target_type', 'step',
      'step', jsonb_build_object(
        'id', s.id,
        'title', s.title,
        'description', s.description,
        'status', s.status,
        'starts_at', s.starts_at,
        'ends_at', s.ends_at,
        'due_at', s.due_at,
        'completed_at', s.completed_at,
        'created_at', s.created_at,
        'metadata', s.metadata
      ),
      'author', jsonb_build_object(
        'full_name', u.full_name,
        'avatar_url', u.avatar_url
      )
    )
    INTO v_payload
    FROM public.timeline_steps s
    LEFT JOIN public.users u ON u.id = s.user_id
    WHERE s.id = v_row.target_id;
  ELSIF v_row.target_type = 'blueprint' THEN
    SELECT jsonb_build_object(
      'target_type', 'blueprint',
      'blueprint', jsonb_build_object(
        'id', b.id,
        'title', b.title,
        'slug', b.slug,
        'description', b.description,
        'interest_id', b.interest_id,
        'subscriber_count', b.subscriber_count,
        'is_published', b.is_published
      ),
      'author', jsonb_build_object(
        'full_name', u.full_name,
        'avatar_url', u.avatar_url
      ),
      'step_count', (
        SELECT COUNT(*) FROM public.blueprint_steps bs WHERE bs.blueprint_id = b.id
      )
    )
    INTO v_payload
    FROM public.timeline_blueprints b
    LEFT JOIN public.users u ON u.id = b.user_id
    WHERE b.id = v_row.target_id;
  END IF;

  IF v_payload IS NULL THEN
    RETURN jsonb_build_object('error', 'target_missing');
  END IF;

  UPDATE public.share_tokens
  SET access_count           = v_row.access_count + 1,
      last_accessed_at       = v_now,
      rate_window_started_at = v_row.rate_window_started_at,
      rate_window_count      = v_row.rate_window_count + 1
  WHERE id = v_row.id;

  RETURN v_payload;
END;
$$;


ALTER FUNCTION "public"."resolve_share_token"("p_token" "text") OWNER TO "postgres";

--
-- TOC entry 1760 (class 1255 OID 204512)
-- Name: respond_to_organization_invite("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."respond_to_organization_invite"("p_invite_token" "text", "p_decision" "text") RETURNS "public"."organization_invites"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_token text := lower(trim(COALESCE(p_invite_token, '')));
  v_decision text := lower(trim(COALESCE(p_decision, '')));
  v_now timestamptz := now();
  v_user_id uuid := auth.uid();
  v_user_email text := lower(trim(COALESCE(auth.jwt() ->> 'email', '')));
  v_invite public.organization_invites;
  v_role text;
  v_membership_metadata jsonb;
  v_activation_allowed boolean := false;
  v_inviter_role text;
BEGIN
  IF v_token = '' THEN
    RAISE EXCEPTION 'Invite token is required.';
  END IF;

  IF v_decision NOT IN ('accepted', 'declined') THEN
    RAISE EXCEPTION 'Decision must be accepted or declined.';
  END IF;

  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required.';
  END IF;

  SELECT *
  INTO v_invite
  FROM public.organization_invites oi
  WHERE lower(oi.invite_token) = v_token
  LIMIT 1
  FOR UPDATE;

  IF v_invite.id IS NULL THEN
    RAISE EXCEPTION 'Invite not found.';
  END IF;

  IF v_invite.status IN ('revoked', 'failed') THEN
    RAISE EXCEPTION 'Invite is no longer active.';
  END IF;

  IF v_invite.invitee_email IS NULL OR lower(trim(v_invite.invitee_email)) <> v_user_email THEN
    RAISE EXCEPTION 'Invite email does not match signed-in user.';
  END IF;

  IF v_invite.status IN ('accepted', 'declined') THEN
    IF v_invite.status = v_decision THEN
      RETURN v_invite;
    END IF;
    RAISE EXCEPTION 'Invite already responded to.';
  END IF;

  IF v_decision = 'accepted' THEN
    v_role := public.map_org_invite_role(v_invite.role_key, v_invite.role_label);
    v_inviter_role := public.get_org_membership_role(v_invite.organization_id, v_invite.invited_by);

    IF v_inviter_role IS NULL THEN
      RAISE EXCEPTION 'Invite issuer is no longer authorized.';
    END IF;

    IF NOT public.can_inviter_issue_org_invite_role(v_inviter_role, v_role) THEN
      RAISE EXCEPTION 'Invite role is not permitted for inviter role.';
    END IF;

    v_membership_metadata := jsonb_build_object(
      'accepted_invite_id', v_invite.id,
      'accepted_invite_token', v_invite.invite_token,
      'accepted_invite_role_label', v_invite.role_label,
      'accepted_invite_at', v_now,
      'resolved_target_role', v_role,
      'inviter_role_at_accept', v_inviter_role
    );

    INSERT INTO public.organization_memberships (
      organization_id,
      user_id,
      role,
      status,
      is_verified,
      verification_source,
      verified_at,
      joined_at,
      metadata
    )
    VALUES (
      v_invite.organization_id,
      v_user_id,
      v_role,
      'active',
      true,
      'invite',
      v_now,
      v_now,
      v_membership_metadata
    )
    ON CONFLICT (organization_id, user_id)
    DO UPDATE
    SET
      role = CASE
        WHEN organization_memberships.status IN ('pending', 'invited', 'inactive', 'rejected')
          THEN EXCLUDED.role
        ELSE organization_memberships.role
      END,
      status = CASE
        WHEN organization_memberships.status IN ('pending', 'invited', 'inactive', 'rejected')
          THEN 'active'
        ELSE organization_memberships.status
      END,
      is_verified = CASE
        WHEN organization_memberships.status IN ('pending', 'invited', 'inactive', 'rejected')
          THEN true
        ELSE organization_memberships.is_verified
      END,
      verification_source = CASE
        WHEN organization_memberships.status IN ('pending', 'invited', 'inactive', 'rejected')
          THEN 'invite'
        ELSE organization_memberships.verification_source
      END,
      verified_at = CASE
        WHEN organization_memberships.status IN ('pending', 'invited', 'inactive', 'rejected')
          THEN v_now
        ELSE organization_memberships.verified_at
      END,
      joined_at = COALESCE(organization_memberships.joined_at, v_now),
      metadata = COALESCE(organization_memberships.metadata, '{}'::jsonb) || v_membership_metadata,
      updated_at = v_now
    RETURNING (
      status IN ('active', 'verified')
    )
    INTO v_activation_allowed;

    IF NOT v_activation_allowed THEN
      RAISE EXCEPTION 'Membership activation failed.';
    END IF;
  END IF;

  UPDATE public.organization_invites oi
  SET
    status = v_decision,
    responded_at = COALESCE(oi.responded_at, v_now)
  WHERE oi.id = v_invite.id
  RETURNING *
  INTO v_invite;

  RETURN v_invite;
END;
$$;


ALTER FUNCTION "public"."respond_to_organization_invite"("p_invite_token" "text", "p_decision" "text") OWNER TO "postgres";

