--
-- TOC entry 1825 (class 1255 OID 245665)
-- Name: revoke_share_token("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."revoke_share_token"("p_token" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_caller UUID := auth.uid();
  v_updated INTEGER;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'authentication required' USING ERRCODE = '42501';
  END IF;

  UPDATE public.share_tokens
  SET revoked_at = now()
  WHERE token = p_token
    AND created_by = v_caller
    AND revoked_at IS NULL;

  GET DIAGNOSTICS v_updated = ROW_COUNT;
  RETURN v_updated > 0;
END;
$$;


