--
-- TOC entry 1633 (class 1255 OID 130880)
-- Name: search_coaches("text"[], numeric, integer, "text", integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."search_coaches"("p_specialties" "text"[] DEFAULT NULL::"text"[], "p_min_rating" numeric DEFAULT NULL::numeric, "p_max_hourly_rate" integer DEFAULT NULL::integer, "p_location" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 20, "p_offset" integer DEFAULT 0) RETURNS TABLE("coach_id" "uuid", "display_name" "text", "profile_image_url" "text", "bio" "text", "specializations" "text"[], "hourly_rate" numeric, "currency" "text", "based_at" "text", "average_rating" numeric, "total_sessions" integer, "is_verified" boolean, "match_score" numeric)
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    cp.id AS coach_id,
    cp.display_name,
    cp.profile_image_url AS profile_photo_url,
    cp.bio,
    cp.specializations AS specialties,
    cp.hourly_rate,
    cp.currency,
    COALESCE(cp.location_name, cp.location_region) AS based_at,
    cm.average_rating,
    COALESCE(cm.total_completed_sessions, 0)::INTEGER AS total_sessions,
    cp.is_verified AS verified,
    1.0::DECIMAL AS match_score
  FROM coach_profiles cp
  LEFT JOIN coach_metrics_view cm ON cp.id = cm.coach_id
  WHERE
    cp.is_active = true
    AND (p_specialties IS NULL OR cp.specializations && p_specialties)
    AND (p_min_rating IS NULL OR COALESCE(cm.average_rating, 0) >= p_min_rating)
    AND (p_max_hourly_rate IS NULL OR cp.hourly_rate <= p_max_hourly_rate)
  ORDER BY cm.average_rating DESC NULLS LAST, cm.total_completed_sessions DESC NULLS LAST
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;


ALTER FUNCTION "public"."search_coaches"("p_specialties" "text"[], "p_min_rating" numeric, "p_max_hourly_rate" integer, "p_location" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";

--
-- TOC entry 1704 (class 1255 OID 166879)
-- Name: search_global_clubs("text", "text", "text", boolean, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."search_global_clubs"("search_query" "text" DEFAULT NULL::"text", "country_filter" "text" DEFAULT NULL::"text", "club_type_filter" "text" DEFAULT NULL::"text", "verified_only" boolean DEFAULT false, "result_limit" integer DEFAULT 50) RETURNS TABLE("id" "uuid", "name" "text", "short_name" "text", "description" "text", "club_type" "text", "country" "text", "city" "text", "logo_url" "text", "verified" boolean, "platform_club_id" "uuid", "member_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    gc.id,
    gc.name,
    gc.short_name,
    gc.description,
    gc.club_type,
    gc.country,
    gc.city,
    gc.logo_url,
    gc.verified,
    gc.platform_club_id,
    COUNT(gcm.id) as member_count
  FROM global_clubs gc
  LEFT JOIN global_club_members gcm ON gcm.global_club_id = gc.id
  WHERE
    (search_query IS NULL OR gc.name ILIKE '%' || search_query || '%')
    AND (country_filter IS NULL OR gc.country_code = country_filter OR gc.country ILIKE '%' || country_filter || '%')
    AND (club_type_filter IS NULL OR gc.club_type = club_type_filter)
    AND (NOT verified_only OR gc.verified = true)
  GROUP BY gc.id
  ORDER BY
    gc.verified DESC,
    COUNT(gcm.id) DESC,
    gc.name ASC
  LIMIT result_limit;
END;
$$;


ALTER FUNCTION "public"."search_global_clubs"("search_query" "text", "country_filter" "text", "club_type_filter" "text", "verified_only" boolean, "result_limit" integer) OWNER TO "postgres";

--
-- TOC entry 1735 (class 1255 OID 190659)
-- Name: set_booking_expiration(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."set_booking_expiration"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
BEGIN
  -- Only set expiration for new pending requests
  IF NEW.expires_at IS NULL AND NEW.status = 'pending' THEN
    NEW.expires_at := NEW.created_at + INTERVAL '48 hours';
  END IF;
  RETURN NEW;
END;
