--
-- TOC entry 1655 (class 1255 OID 138065)
-- Name: set_practice_invite_code("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."set_practice_invite_code"("session_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  new_code TEXT;
BEGIN
  -- Generate unique code (reuses existing generate_invite_code function)
  LOOP
    new_code := generate_invite_code();
    EXIT WHEN NOT EXISTS (
      SELECT 1 FROM practice_sessions WHERE invite_code = new_code
    ) AND NOT EXISTS (
      SELECT 1 FROM team_race_entries WHERE invite_code = new_code
    );
  END LOOP;

  -- Update session with new code
  UPDATE practice_sessions
  SET invite_code = new_code
  WHERE id = session_id;

  RETURN new_code;
END;
$$;


