--
-- TOC entry 1674 (class 1255 OID 154898)
-- Name: set_race_collaborator_invite_code("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."set_race_collaborator_invite_code"("p_collaborator_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  new_code TEXT;
  max_attempts INTEGER := 10;
  attempts INTEGER := 0;
BEGIN
  LOOP
    new_code := generate_race_collaborator_invite_code();
    BEGIN
      UPDATE race_collaborators SET invite_code = new_code WHERE id = p_collaborator_id;
      RETURN new_code;
    EXCEPTION WHEN unique_violation THEN
      attempts := attempts + 1;
      IF attempts >= max_attempts THEN
        RAISE EXCEPTION 'Could not generate unique invite code';
      END IF;
    END;
  END LOOP;
END;
$$;


