-- Name: FUNCTION "step_arch_e_backfill_batch"("batch_size" integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."step_arch_e_backfill_batch"("batch_size" integer) IS 'Step Arch E — processes one page of legacy-flat-field rows into v2 sections[]. Idempotent. Run repeatedly until it returns 0.';


--
-- TOC entry 1822 (class 1255 OID 245603)
-- Name: step_review_parse_telegram_stamp("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."step_review_parse_telegram_stamp"("content" "text") RETURNS TABLE("captured_date" "date", "has_stamp" boolean)
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  best date := NULL;
BEGIN
  IF content IS NULL OR length(content) = 0 THEN
    captured_date := NULL;
    has_stamp := false;
    RETURN NEXT;
    RETURN;
  END IF;

  BEGIN
    SELECT MAX((m)[1]::date) INTO best
    FROM regexp_matches(content, '\[(\d{4}-\d{2}-\d{2}) via Telegram\]', 'g') AS m;
  EXCEPTION WHEN OTHERS THEN
    best := NULL;
  END;

  captured_date := best;
  has_stamp := best IS NOT NULL;
  RETURN NEXT;
END;
$$;


ALTER FUNCTION "public"."step_review_parse_telegram_stamp"("content" "text") OWNER TO "postgres";

--
-- TOC entry 1782 (class 1255 OID 225521)
-- Name: sync_new_member_org_tier(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_new_member_org_tier"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
DECLARE
  org_sub RECORD;
BEGIN
  -- Only run when membership becomes active/verified
  IF NEW.status NOT IN ('active', 'verified') THEN
    RETURN NEW;
  END IF;

  -- Check if org has active subscription
  SELECT * INTO org_sub
  FROM organization_subscriptions
  WHERE organization_id = NEW.organization_id
  AND status = 'active'
  LIMIT 1;

  IF FOUND THEN
    -- Only upgrade free self-paying users
    UPDATE users SET
      subscription_tier = org_sub.member_tier,
      subscription_status = 'active',
      tier_source = 'organization'
    WHERE id = NEW.user_id
    AND tier_source = 'self'
    AND subscription_tier = 'free';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_new_member_org_tier"() OWNER TO "postgres";

--
-- TOC entry 1781 (class 1255 OID 225519)
-- Name: sync_org_member_tiers(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_org_member_tiers"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog', 'public'
    AS $$
BEGIN
  -- When org subscription is active, grant members the appropriate tier
  IF NEW.status = 'active' THEN
    UPDATE users SET
      subscription_tier = NEW.member_tier,
      subscription_status = 'active',
      tier_source = 'organization'
    WHERE id IN (
      SELECT user_id FROM organization_memberships
      WHERE organization_id = NEW.organization_id
      AND status IN ('active', 'verified')
    )
    AND (
      -- Only upgrade free self-paying users or update existing org-granted users
      (tier_source = 'self' AND subscription_tier = 'free')
      OR tier_source = 'organization'
    );
  END IF;

  -- When org subscription is cancelled/expired, reset org-granted tiers
  IF NEW.status IN ('cancelled', 'expired')
     AND (TG_OP = 'INSERT' OR OLD.status = 'active') THEN
    UPDATE users SET
      subscription_tier = 'free',
      subscription_status = NULL,
      tier_source = 'self'
    WHERE id IN (
      SELECT user_id FROM organization_memberships
      WHERE organization_id = NEW.organization_id
    )
    AND tier_source = 'organization';
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."sync_org_member_tiers"() OWNER TO "postgres";

