-- TOC entry 1591 (class 1255 OID 31890)
-- Name: update_coach_rating_after_review(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_coach_rating_after_review"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_avg_rating NUMERIC;
  v_total_sessions INTEGER;
BEGIN
  IF NEW.rating IS NOT NULL AND (OLD IS NULL OR OLD.rating IS NULL OR NEW.rating != OLD.rating) THEN
    SELECT
      COALESCE(AVG(rating), 0.0),
      COUNT(*)
    INTO v_avg_rating, v_total_sessions
    FROM public.coaching_sessions
    WHERE coach_id = NEW.coach_id
      AND rating IS NOT NULL
      AND status = 'completed';

    UPDATE public.coach_profiles
    SET
      rating = v_avg_rating,
      total_sessions = v_total_sessions,
      updated_at = NOW()
    WHERE id = NEW.coach_id;
  END IF;

  RETURN NEW;
END;
$$;


