--
-- TOC entry 1610 (class 1255 OID 62926)
-- Name: update_event_earnings(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_event_earnings"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_event RECORD;
BEGIN
    SELECT e.club_id, e.start_date, e.end_date
    INTO v_event
    FROM public.club_events e
    WHERE e.id = COALESCE(NEW.event_id, OLD.event_id);

    INSERT INTO public.club_event_earnings (
        club_id,
        event_id,
        total_registrations,
        total_revenue,
        platform_fees,
        club_payout,
        start_date,
        end_date
    )
    SELECT
        v_event.club_id,
        COALESCE(NEW.event_id, OLD.event_id),
        COUNT(*)::INTEGER,
        COALESCE(SUM(amount_paid), 0),
        COALESCE(SUM(platform_fee), 0),
        COALESCE(SUM(club_payout), 0),
        v_event.start_date,
        v_event.end_date
    FROM public.event_registrations
    WHERE event_id = COALESCE(NEW.event_id, OLD.event_id)
        AND payment_status = 'paid'
    ON CONFLICT (event_id) DO UPDATE SET
        total_registrations = EXCLUDED.total_registrations,
        total_revenue = EXCLUDED.total_revenue,
        platform_fees = EXCLUDED.platform_fees,
        club_payout = EXCLUDED.club_payout,
        updated_at = NOW();

    RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION "public"."update_event_earnings"() OWNER TO "postgres";

