--
-- TOC entry 1692 (class 1255 OID 166397)
-- Name: update_regatta_comment_count(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_regatta_comment_count"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    UPDATE regattas SET comment_count = comment_count + 1 WHERE id = NEW.regatta_id;
    RETURN NEW;
  ELSIF TG_OP = 'DELETE' THEN
    UPDATE regattas SET comment_count = GREATEST(0, comment_count - 1) WHERE id = OLD.regatta_id;
    RETURN OLD;
  ELSIF TG_OP = 'UPDATE' THEN
    -- Handle soft delete
    IF OLD.is_deleted = false AND NEW.is_deleted = true THEN
      UPDATE regattas SET comment_count = GREATEST(0, comment_count - 1) WHERE id = NEW.regatta_id;
    ELSIF OLD.is_deleted = true AND NEW.is_deleted = false THEN
      UPDATE regattas SET comment_count = comment_count + 1 WHERE id = NEW.regatta_id;
    END IF;
    RETURN NEW;
  END IF;
  RETURN NULL;
END;
$$;


ALTER FUNCTION "public"."update_regatta_comment_count"() OWNER TO "postgres";

