--
-- TOC entry 1615 (class 1255 OID 64537)
-- Name: update_session_progress(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_session_progress"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_progress INTEGER;
BEGIN
    SELECT completion_percentage
    INTO v_progress
    FROM public.get_onboarding_progress(COALESCE(NEW.session_id, OLD.session_id));

    UPDATE public.club_onboarding_sessions
    SET progress_percentage = v_progress,
        updated_at = NOW()
    WHERE id = COALESCE(NEW.session_id, OLD.session_id);

    RETURN COALESCE(NEW, OLD);
END;
$$;


