--
-- TOC entry 1725 (class 1255 OID 175660)
-- Name: update_user_from_firebase("uuid", "text", "text", "text", "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_user_from_firebase"("p_user_id" "uuid", "p_firebase_uid" "text", "p_full_name" "text" DEFAULT NULL::"text", "p_avatar_url" "text" DEFAULT NULL::"text", "p_boat_class" "text" DEFAULT NULL::"text", "p_club_name" "text" DEFAULT NULL::"text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Update the user profile with Firebase data
  UPDATE users
  SET
    firebase_uid = COALESCE(firebase_uid, p_firebase_uid),
    full_name = COALESCE(full_name, p_full_name),
    avatar_url = COALESCE(avatar_url, p_avatar_url),
    auth_source = CASE
      WHEN auth_source = 'native' AND firebase_uid IS NULL
      THEN 'dragon_worlds'
      ELSE auth_source
    END,
    updated_at = now()
  WHERE id = p_user_id;

  -- If boat_class provided, try to look up and associate
  IF p_boat_class IS NOT NULL THEN
    -- Store in metadata for now, can be processed later
    UPDATE users
    SET metadata = COALESCE(metadata, '{}'::jsonb) ||
        jsonb_build_object('dragon_worlds_boat_class', p_boat_class)
    WHERE id = p_user_id;
  END IF;

  -- If club_name provided, store in metadata
  IF p_club_name IS NOT NULL THEN
    UPDATE users
    SET metadata = COALESCE(metadata, '{}'::jsonb) ||
        jsonb_build_object('dragon_worlds_club', p_club_name)
    WHERE id = p_user_id;
  END IF;
END;
$$;


ALTER FUNCTION "public"."update_user_from_firebase"("p_user_id" "uuid", "p_firebase_uid" "text", "p_full_name" "text", "p_avatar_url" "text", "p_boat_class" "text", "p_club_name" "text", "p_metadata" "jsonb") OWNER TO "postgres";

