-- TOC entry 1585 (class 1255 OID 29204)
-- Name: update_user_location_context("uuid", "text", "text", "point", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_user_location_context"("p_user_id" "uuid", "p_location_name" "text", "p_location_region" "text", "p_coordinates" "point", "p_detection_method" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.user_location_context (
    user_id,
    current_location_name,
    current_location_region,
    current_location_coordinates,
    detection_method,
    last_updated
  )
  VALUES (
    p_user_id,
    p_location_name,
    p_location_region,
    p_coordinates,
    p_detection_method,
    NOW()
  )
  ON CONFLICT (user_id) DO UPDATE SET
    current_location_name = EXCLUDED.current_location_name,
    current_location_region = EXCLUDED.current_location_region,
    current_location_coordinates = EXCLUDED.current_location_coordinates,
    detection_method = EXCLUDED.detection_method,
    last_updated = NOW();
END;
$$;


