--
-- TOC entry 1593 (class 1255 OID 32005)
-- Name: venues_within_bbox(double precision, double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."venues_within_bbox"("min_lon" double precision, "min_lat" double precision, "max_lon" double precision, "max_lat" double precision) RETURNS TABLE("id" "text", "name" "text", "latitude" double precision, "longitude" double precision, "region" "text")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    sv.id,
    sv.name,
    sv.coordinates_lat::DOUBLE PRECISION AS latitude,
    sv.coordinates_lng::DOUBLE PRECISION AS longitude,
    sv.region
  FROM sailing_venues sv
  WHERE sv.coordinates_lat IS NOT NULL
    AND sv.coordinates_lng IS NOT NULL
    AND sv.coordinates_lat BETWEEN min_lat AND max_lat
    AND sv.coordinates_lng BETWEEN min_lon AND max_lon
  ORDER BY sv.name ASC
  LIMIT 10;
END;
$$;


ALTER FUNCTION "public"."venues_within_bbox"("min_lon" double precision, "min_lat" double precision, "max_lon" double precision, "max_lat" double precision) OWNER TO "postgres";

--
-- TOC entry 1594 (class 1255 OID 33232)
-- Name: venues_within_radius(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."venues_within_radius"("lat" double precision, "lng" double precision, "radius_km" double precision DEFAULT 50) RETURNS TABLE("id" "text", "name" "text", "city" "text", "country" "text", "latitude" double precision, "longitude" double precision, "venue_type" "text", "distance_km" double precision)
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    v.id,
    v.name,
    SPLIT_PART(v.formatted_address, ',', 1) AS city,
    v.country,
    v.coordinates_lat::DOUBLE PRECISION AS latitude,
    v.coordinates_lng::DOUBLE PRECISION AS longitude,
    v.venue_type,
    ST_Distance(
      ST_SetSRID(ST_MakePoint(lng, lat), 4326)::geography,
      ST_SetSRID(ST_MakePoint(v.coordinates_lng::DOUBLE PRECISION, v.coordinates_lat::DOUBLE PRECISION), 4326)::geography
    ) / 1000 AS distance_km
  FROM sailing_venues v
  WHERE
    v.coordinates_lat IS NOT NULL
    AND v.coordinates_lng IS NOT NULL
    AND ST_DWithin(
      ST_SetSRID(ST_MakePoint(lng, lat), 4326)::geography,
      ST_SetSRID(ST_MakePoint(v.coordinates_lng::DOUBLE PRECISION, v.coordinates_lat::DOUBLE PRECISION), 4326)::geography,
      radius_km * 1000
    )
  ORDER BY distance_km ASC;
END;
$$;


ALTER FUNCTION "public"."venues_within_radius"("lat" double precision, "lng" double precision, "radius_km" double precision) OWNER TO "postgres";

--
-- TOC entry 12609 (class 0 OID 0)
