-- Name: FUNCTION "venues_within_radius"("lat" double precision, "lng" double precision, "radius_km" double precision); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."venues_within_radius"("lat" double precision, "lng" double precision, "radius_km" double precision) IS 'Find sailing venues within a specified radius of GPS coordinates. Returns venues ordered by distance (closest first).';


