--
-- TOC entry 530 (class 1259 OID 103392)
-- Name: ai_insights_summary; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."ai_insights_summary" WITH ("security_invoker"='true') AS
 SELECT "r"."name" AS "regatta_name",
    "r"."start_date",
    "r"."status" AS "regatta_status",
    "aa"."analysis_type",
    "aa"."confidence_score",
    "aa"."created_at" AS "analysis_created",
    "p"."first_name",
    "p"."last_name",
    "count"("aa"."id") OVER (PARTITION BY "aa"."regatta_id") AS "total_analyses_for_regatta"
   FROM (("public"."ai_analyses" "aa"
     JOIN "public"."regattas" "r" ON (("aa"."regatta_id" = "r"."id")))
     JOIN "public"."profiles" "p" ON (("aa"."user_id" = "p"."id")))
  WHERE ("aa"."created_at" >= ("now"() - '7 days'::interval))
  ORDER BY "aa"."created_at" DESC;


ALTER VIEW "public"."ai_insights_summary" OWNER TO "postgres";

