--
-- TOC entry 551 (class 1259 OID 136052)
-- Name: coach_feedback_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."coach_feedback_view" WITH ("security_invoker"='on') AS
 SELECT "sf"."id" AS "feedback_id",
    "sf"."session_id",
    "sf"."rating",
    "sf"."feedback_text",
    "sf"."communication_rating",
    "sf"."expertise_rating",
    "sf"."value_rating",
    "sf"."skill_improvement",
    "sf"."confidence_change",
    "sf"."would_recommend",
    "sf"."created_at" AS "feedback_date",
    "cs"."session_type",
    "cs"."completed_at" AS "session_date",
    "cs"."duration_minutes",
    "cs"."coach_id",
    "cp"."display_name" AS "coach_name",
    COALESCE("cs"."sailor_id", "cs"."student_id") AS "sailor_id",
    "u"."full_name" AS "sailor_name",
    "u"."email" AS "sailor_email"
   FROM ((("public"."session_feedback" "sf"
     JOIN "public"."coaching_sessions" "cs" ON (("sf"."session_id" = "cs"."id")))
     JOIN "public"."coach_profiles" "cp" ON (("cs"."coach_id" = "cp"."id")))
     LEFT JOIN "public"."users" "u" ON ((COALESCE("cs"."sailor_id", "cs"."student_id") = "u"."id")))
  WHERE ("sf"."public" = true);


