--
-- TOC entry 552 (class 1259 OID 136057)
-- Name: coach_sailor_sessions_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."coach_sailor_sessions_view" WITH ("security_invoker"='on') AS
 SELECT "cs"."id" AS "session_id",
    "cs"."coach_id",
    COALESCE("cs"."sailor_id", "cs"."student_id") AS "sailor_id",
    "cs"."session_type",
    "cs"."duration_minutes",
    "cs"."scheduled_at",
    "cs"."completed_at",
    "cs"."status",
    "cs"."location_notes",
    "cs"."focus_areas",
    "cs"."goals",
    "cs"."session_notes",
    "cs"."homework",
    COALESCE("cs"."fee_amount", "cs"."total_amount_cents") AS "fee_amount",
    "cs"."currency",
    "cs"."paid",
    "cs"."created_at",
    "cs"."updated_at",
    "cs"."venue_id",
    "cp"."display_name" AS "coach_name",
    "cp"."profile_image_url" AS "coach_photo",
    "cp"."specializations" AS "coach_specialties",
    "u"."full_name" AS "sailor_name",
    "u"."email" AS "sailor_email",
    "sf"."rating" AS "feedback_rating",
    "sf"."feedback_text",
    "sf"."skill_improvement",
    "sf"."would_recommend"
   FROM ((("public"."coaching_sessions" "cs"
     LEFT JOIN "public"."coach_profiles" "cp" ON (("cs"."coach_id" = "cp"."id")))
     LEFT JOIN "public"."users" "u" ON ((COALESCE("cs"."sailor_id", "cs"."student_id") = "u"."id")))
     LEFT JOIN "public"."session_feedback" "sf" ON (("cs"."id" = "sf"."session_id")));


