--
-- TOC entry 629 (class 1259 OID 175700)
-- Name: communities_with_stats; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."communities_with_stats" WITH ("security_invoker"='true') AS
 SELECT "c"."id",
    "c"."name",
    "c"."slug",
    "c"."description",
    "c"."community_type",
    "c"."category_id",
    "c"."icon_url",
    "c"."banner_url",
    "c"."member_count",
    (( SELECT "count"(*) AS "count"
           FROM "public"."venue_discussions" "vd"
          WHERE (("vd"."community_id" = "c"."id") AND ("vd"."is_public" = true))))::integer AS "post_count",
    "c"."created_by",
    "c"."is_official",
    "c"."is_verified",
    "c"."linked_entity_type",
    "c"."linked_entity_id",
    "c"."metadata",
    "c"."created_at",
    "c"."updated_at",
    "c"."last_activity_at",
    "cat"."display_name" AS "category_name",
    "cat"."icon" AS "category_icon",
    "cat"."color" AS "category_color",
    ( SELECT "count"(*) AS "count"
           FROM "public"."venue_discussions" "vd"
          WHERE (("vd"."community_id" = "c"."id") AND ("vd"."created_at" > ("now"() - '24:00:00'::interval)))) AS "posts_last_24h",
    ( SELECT "count"(DISTINCT "cm"."user_id") AS "count"
           FROM "public"."community_memberships" "cm"
          WHERE (("cm"."community_id" = "c"."id") AND ("cm"."joined_at" > ("now"() - '7 days'::interval)))) AS "new_members_7d"
   FROM ("public"."communities" "c"
     LEFT JOIN "public"."community_categories" "cat" ON (("c"."category_id" = "cat"."id")));


ALTER VIEW "public"."communities_with_stats" OWNER TO "postgres";

