--
-- TOC entry 623 (class 1259 OID 172926)
-- Name: crew_threads_with_details; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."crew_threads_with_details" WITH ("security_invoker"='true') AS
 SELECT "ct"."id",
    "ct"."name",
    "ct"."owner_id",
    "ct"."avatar_emoji",
    "ct"."thread_type",
    "ct"."created_at",
    "ct"."updated_at",
    "ctm"."user_id" AS "member_user_id",
    "ctm"."role",
    "ctm"."last_read_at",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."crew_thread_messages" "msg"
          WHERE (("msg"."thread_id" = "ct"."id") AND ("msg"."created_at" > COALESCE("ctm"."last_read_at", "ct"."created_at")) AND ("msg"."user_id" <> "ctm"."user_id"))) AS "unread_count",
    ( SELECT "msg"."message"
           FROM "public"."crew_thread_messages" "msg"
          WHERE ("msg"."thread_id" = "ct"."id")
          ORDER BY "msg"."created_at" DESC
         LIMIT 1) AS "last_message",
    ( SELECT "msg"."user_id"
           FROM "public"."crew_thread_messages" "msg"
          WHERE ("msg"."thread_id" = "ct"."id")
          ORDER BY "msg"."created_at" DESC
         LIMIT 1) AS "last_message_user_id",
    ( SELECT "msg"."created_at"
           FROM "public"."crew_thread_messages" "msg"
          WHERE ("msg"."thread_id" = "ct"."id")
          ORDER BY "msg"."created_at" DESC
         LIMIT 1) AS "last_message_at"
   FROM ("public"."crew_threads" "ct"
     JOIN "public"."crew_thread_members" "ctm" ON (("ctm"."thread_id" = "ct"."id")));


ALTER VIEW "public"."crew_threads_with_details" OWNER TO "postgres";

