--
-- TOC entry 532 (class 1259 OID 103416)
-- Name: race_analytics; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."race_analytics" WITH ("security_invoker"='true') AS
 SELECT "r"."id" AS "regatta_id",
    "r"."name" AS "regatta_name",
    "r"."start_date",
    "r"."status",
    "count"(DISTINCT "bp"."boat_id") AS "participating_boats",
    "round"("avg"("bp"."speed_knots"), 2) AS "average_speed",
    "round"("max"("bp"."speed_knots"), 2) AS "top_speed",
    "min"("bp"."timestamp") AS "race_start_time",
    "max"("bp"."timestamp") AS "last_position_update"
   FROM ("public"."regattas" "r"
     LEFT JOIN "public"."boat_positions" "bp" ON (("r"."id" = "bp"."regatta_id")))
  GROUP BY "r"."id", "r"."name", "r"."start_date", "r"."status";


ALTER VIEW "public"."race_analytics" OWNER TO "postgres";

