--
-- TOC entry 558 (class 1259 OID 136530)
-- Name: sail_inventory_with_health; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."sail_inventory_with_health" WITH ("security_invoker"='true') AS
 SELECT "be"."id",
    "be"."boat_id",
    "be"."sailor_id",
    "be"."custom_name",
    "be"."category" AS "sail_type",
    "be"."subcategory",
    "be"."serial_number",
    "be"."purchase_date",
    "be"."condition",
    "be"."status",
    "be"."photos",
    "be"."specifications",
    "be"."total_usage_hours",
    "be"."total_races_used",
    "sed"."sailmaker",
    "sed"."sail_number",
    "sed"."design_name",
    "sed"."material",
    "sed"."construction_type",
    "sed"."area_sqm",
    "sed"."optimal_wind_range_min",
    "sed"."optimal_wind_range_max",
    "sed"."estimated_race_hours",
    "sed"."estimated_race_hours_remaining",
    "sed"."primary_use",
    "latest_inspection"."id" AS "last_inspection_id",
    "latest_inspection"."overall_condition_score" AS "last_inspection_score",
    "latest_inspection"."inspection_date" AS "last_inspection_date",
    "latest_inspection"."race_ready" AS "last_inspection_race_ready",
    "latest_inspection"."ai_recommendations",
    "latest_inspection"."issues_detected",
        CASE
            WHEN ("latest_inspection"."overall_condition_score" >= 80) THEN 'good'::"text"
            WHEN ("latest_inspection"."overall_condition_score" >= 60) THEN 'fair'::"text"
            WHEN ("latest_inspection"."overall_condition_score" >= 40) THEN 'poor'::"text"
            WHEN ("latest_inspection"."overall_condition_score" IS NOT NULL) THEN 'critical'::"text"
            ELSE 'unknown'::"text"
        END AS "condition_status",
        CASE
            WHEN ("latest_inspection"."inspection_date" < ("now"() - '30 days'::interval)) THEN true
            ELSE false
        END AS "inspection_overdue"
   FROM (("public"."boat_equipment" "be"
     LEFT JOIN "public"."sail_equipment_details" "sed" ON (("be"."id" = "sed"."equipment_id")))
     LEFT JOIN LATERAL ( SELECT "si"."id",
            "si"."equipment_id",
            "si"."sailor_id",
            "si"."boat_id",
            "si"."inspection_date",
            "si"."inspection_type",
            "si"."inspection_mode",
            "si"."overall_condition_score",
            "si"."race_ready",
            "si"."ai_summary",
            "si"."ai_recommendations",
            "si"."zone_scores",
            "si"."issues_detected",
            "si"."photos",
            "si"."notes",
            "si"."created_at",
            "si"."updated_at"
           FROM "public"."sail_inspections" "si"
          WHERE ("si"."equipment_id" = "be"."id")
          ORDER BY "si"."inspection_date" DESC
         LIMIT 1) "latest_inspection" ON (true))
  WHERE ("be"."category" = ANY (ARRAY['mainsail'::"text", 'jib'::"text", 'genoa'::"text", 'spinnaker'::"text", 'code_zero'::"text", 'storm_jib'::"text", 'trysail'::"text"]));


ALTER VIEW "public"."sail_inventory_with_health" OWNER TO "postgres";

