--
-- TOC entry 529 (class 1259 OID 103387)
-- Name: saved_venues_with_details; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."saved_venues_with_details" WITH ("security_invoker"='true') AS
 SELECT COALESCE("sv"."id", "s"."venue_id") AS "id",
    "s"."user_id",
    COALESCE("sv"."name", "s"."location_name", 'Unknown Venue'::"text") AS "name",
    COALESCE("sv"."country", 'Unknown'::"text") AS "country",
    COALESCE("sv"."region", "s"."location_region", 'Unknown'::"text") AS "region",
    "sv"."coordinates_lat",
    "sv"."coordinates_lng",
    "s"."id" AS "saved_venue_id",
    "s"."service_type",
    "s"."location_name",
    "s"."location_region",
    "s"."notes",
    "s"."is_home_venue",
    "s"."created_at" AS "saved_at",
    "sv"."venue_type",
    "sv"."time_zone"
   FROM ("public"."saved_venues" "s"
     LEFT JOIN "public"."sailing_venues" "sv" ON (("sv"."id" = "s"."venue_id")));


ALTER VIEW "public"."saved_venues_with_details" OWNER TO "postgres";

