--
-- TOC entry 507 (class 1259 OID 77248)
-- Name: timeline_events; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."timeline_events" WITH ("security_invoker"='true') AS
 WITH "regatta_events" AS (
         SELECT "r"."id",
            'yachtracing'::"text" AS "domain_id",
            "r"."name" AS "title",
            "r"."start_date" AS "start_time",
                CASE
                    WHEN ("r"."start_date" > "now"()) THEN 'upcoming'::"text"
                    WHEN (COALESCE("r"."end_date", "r"."start_date") >= "now"()) THEN 'active'::"text"
                    ELSE 'completed'::"text"
                END AS "status",
            NULLIF(COALESCE(TRIM(BOTH '"'::"text" FROM ("r"."location")::"text"), ("r"."metadata" ->> 'venue'::"text")), ''::"text") AS "location",
            COALESCE(NULLIF(("r"."metadata" ->> 'summary'::"text"), ''::"text"), NULLIF("r"."description", ''::"text"), "concat_ws"(' • '::"text", "to_char"("r"."start_date", 'Mon DD'::"text"), "to_char"("r"."start_date", 'HH24:MI'::"text"), NULLIF(COALESCE(TRIM(BOTH '"'::"text" FROM ("r"."location")::"text"), ("r"."metadata" ->> 'venue'::"text")), ''::"text"))) AS "summary"
           FROM "public"."regattas" "r"
          WHERE ("r"."start_date" IS NOT NULL)
        ), "clinical_events" AS (
         SELECT "cs"."id",
            COALESCE(NULLIF("cs"."domain_id", ''::"text"), 'nursing'::"text") AS "domain_id",
            "cs"."scenario_title" AS "title",
            "cs"."scheduled_start" AS "start_time",
                CASE
                    WHEN ("cs"."scheduled_start" > "now"()) THEN 'upcoming'::"text"
                    ELSE 'active'::"text"
                END AS "status",
            NULLIF("cs"."unit_name", ''::"text") AS "location",
            COALESCE(NULLIF("cs"."learning_focus", ''::"text"), NULLIF("cs"."notes", ''::"text")) AS "summary"
           FROM "public"."clinical_sessions" "cs"
        )
 SELECT "regatta_events"."id",
    "regatta_events"."domain_id",
    "regatta_events"."title",
    "regatta_events"."start_time",
    "regatta_events"."status",
    "regatta_events"."location",
    "regatta_events"."summary"
   FROM "regatta_events"
UNION ALL
 SELECT "clinical_events"."id",
    "clinical_events"."domain_id",
    "clinical_events"."title",
    "clinical_events"."start_time",
    "clinical_events"."status",
    "clinical_events"."location",
    "clinical_events"."summary"
   FROM "clinical_events";


ALTER VIEW "public"."timeline_events" OWNER TO "postgres";

