-- TOC entry 542 (class 1259 OID 130698)
-- Name: user_profiles; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW "public"."user_profiles" WITH ("security_invoker"='true') AS
 SELECT "id",
    COALESCE(NULLIF("btrim"(("to_jsonb"("u".*) ->> 'full_name'::"text")), ''::"text"), "split_part"(COALESCE(("to_jsonb"("u".*) ->> 'email'::"text"), ''::"text"), '@'::"text", 1), 'Sailor'::"text") AS "full_name",
    ("to_jsonb"("u".*) ->> 'avatar_url'::"text") AS "avatar_url",
    (("to_jsonb"("u".*) ->> 'email'::"text"))::character varying(255) AS "email",
    (("to_jsonb"("u".*) ->> 'created_at'::"text"))::timestamp with time zone AS "created_at"
   FROM "public"."users" "u";


ALTER VIEW "public"."user_profiles" OWNER TO "postgres";

